# ── AccuKnox official logo and icon (embedded from accuknox.com) ─────────────
# Full logo with text: accuknox-logo-2.png (fetched from accuknox.com)
ACCUKNOX_LOGO_DATA_URI = 'data:image/png;base64,'

# Icon-only (favicon): accuknoxfavicon.png (40x40, fetched from accuknox.com)
ACCUKNOX_ICON_DATA_URI = 'data:image/png;base64,'

def _logo_img(height: int = 28, extra_style: str = "") -> str:
    """Full AccuKnox logo (icon + wordmark) as <img>."""
    return (f'<img src="{ACCUKNOX_LOGO_DATA_URI}" alt="AccuKnox" '
            f'style="height:{height}px;object-fit:contain;display:block;{extra_style}">')

def _icon_img(size: int = 32, extra_style: str = "") -> str:
    """AccuKnox icon-only mark as <img>."""
    return (f'<img src="{ACCUKNOX_ICON_DATA_URI}" alt="AccuKnox" '
            f'style="width:{size}px;height:{size}px;object-fit:contain;{extra_style}">')

# Watermark: the icon-only PNG tiled as background via base64 data URI
def _watermark_css_value() -> str:
    return f'url("{ACCUKNOX_ICON_DATA_URI}")'

