# ── Framework mapping loader ──────────────────────────────────────────────────

_FW_CATALOGUE: dict | None = None

def _load_frameworks() -> dict:
    """Load frameworks.yaml once and cache. Returns {finding_id: [refs], colors: {...}}."""
    global _FW_CATALOGUE
    if _FW_CATALOGUE is not None:
        return _FW_CATALOGUE
    try:
        import yaml
        fw_path = Path(__file__).parent / "frameworks.yaml"
        with open(fw_path, encoding="utf-8") as fh:
            data = yaml.safe_load(fh)
        _FW_CATALOGUE = {
            "findings": data.get("findings", {}),
            "colors":   data.get("framework_colors", {}),
        }
    except Exception:
        _FW_CATALOGUE = {"findings": {}, "colors": {}}
    return _FW_CATALOGUE


def _compliance_posture(report: SecurityReport) -> dict[str, list[dict]]:
    """
    Returns {framework_name: [{id, name, url, severity, finding_id}, ...]}
    Only includes frameworks where at least one finding is triggered.
    """
    fw = _load_frameworks()
    all_findings = []
    for result in [report.provenance, report.adversarial,
                   report.privacy, report.file_security]:
        if result:
            all_findings.extend(result.findings)

    sev_map = {f.id: f.severity for f in all_findings}
    triggered_ids = set(sev_map)

    SEV_ORDER = {Severity.CRITICAL: 0, Severity.HIGH: 1, Severity.MEDIUM: 2,
                 Severity.LOW: 3, Severity.INFO: 4, Severity.UNKNOWN: 5}

    posture: dict[str, list[dict]] = {}
    for fid, refs in fw["findings"].items():
        if fid not in triggered_ids:
            continue
        severity = sev_map[fid]
        for ref in refs:
            fname = ref.get("framework", "")
            if fname not in posture:
                posture[fname] = []
            # Deduplicate by ref id within each framework
            if not any(r["ref_id"] == ref["id"] for r in posture[fname]):
                posture[fname].append({
                    "ref_id":     ref["id"],
                    "name":       ref.get("name", ""),
                    "url":        ref.get("url", "#"),
                    "severity":   severity,
                    "finding_id": fid,
                })

    # Sort each framework's list by severity (worst first)
    for items in posture.values():
        items.sort(key=lambda x: SEV_ORDER.get(x["severity"], 5))

    return posture


# Ordered list of all tracked frameworks for consistent display
_ALL_FRAMEWORKS = [
    "OWASP LLM Top 10",
    "MITRE ATLAS",
    "MITRE ATT&CK",
    "NIST AI RMF",
    "EU AI Act",
    "CWE",
    "ISO/IEC 42001",
]


def _compliance_section(report: SecurityReport) -> str:
    """Render the compliance posture dashboard for a single report."""
    fw      = _load_frameworks()
    colors  = fw["colors"]
    posture = _compliance_posture(report)

    SEV_ORDER = {Severity.CRITICAL: 0, Severity.HIGH: 1, Severity.MEDIUM: 2,
                 Severity.LOW: 3, Severity.INFO: 4, Severity.UNKNOWN: 5}

    def worst_sev(items: list[dict]) -> Severity:
        return min(items, key=lambda x: SEV_ORDER.get(x["severity"], 5))["severity"] if items else Severity.INFO

    cards = ""
    for fname in _ALL_FRAMEWORKS:
        col    = colors.get(fname, {})
        hdr_bg = col.get("fg", C["text_muted"])
        hdr_fg = "#FFFFFF"
        items  = posture.get(fname, [])
        triggered = len(items)

        if triggered == 0:
            body = (
                f'<div style="display:flex;align-items:center;gap:6px;padding:6px 0;'
                f'color:{C["pass_"]};font-size:11px;font-weight:600">'
                f'{_icon("check", 13, C["pass_"])} No violations detected</div>'
            )
            card_border = C["pass_"]
        else:
            ws = worst_sev(items)
            ws_fg, ws_bg = SEV_COLOR[ws]
            card_border = ws_fg
            chips = "".join(
                (lambda ref_id=r["ref_id"], rurl=r["url"], rname=r["name"],
                              sfg=SEV_COLOR[r["severity"]][0], sbg=SEV_COLOR[r["severity"]][1]:
                    f'<a href="{html.escape(rurl)}" target="_blank" rel="noopener" '
                    f'title="{html.escape(rname)}" '
                    f'style="display:inline-flex;align-items:center;gap:3px;padding:2px 7px;'
                    f'border-radius:4px;background:{sbg};color:{sfg};font-size:10px;font-weight:700;'
                    f'text-decoration:none;border:1px solid {sfg}30;white-space:nowrap">'
                    f'{html.escape(ref_id)}</a>'
                )()
                for r in items
            )
            body = f'<div style="display:flex;flex-wrap:wrap;gap:5px;padding:6px 0">{chips}</div>'

        cards += (
            f'<div style="background:{C["bg_card"]};border:1px solid {C["border"]};'
            f'border-top:3px solid {card_border};border-radius:8px;overflow:hidden;'
            f'box-shadow:0 1px 3px #0000000A">'
            f'<div style="padding:8px 12px;background:{hdr_bg};'
            f'display:flex;justify-content:space-between;align-items:center">'
            f'  <span style="font-size:11px;font-weight:800;color:{hdr_fg};'
            f'  text-transform:uppercase;letter-spacing:0.4px">{html.escape(fname)}</span>'
            f'  <span style="font-size:10px;font-weight:700;color:{hdr_fg}CC;'
            f'  padding:1px 6px;border-radius:8px;background:#FFFFFF22">'
            f'  {triggered} violation{"s" if triggered != 1 else ""}</span>'
            f'</div>'
            f'<div style="padding:6px 12px 10px">{body}</div>'
            f'</div>'
        )

    total_fw_hit = sum(1 for f in _ALL_FRAMEWORKS if f in posture)
    return (
        f'<div style="padding:4px 0 8px">'
        f'<div style="display:flex;align-items:center;gap:8px;margin-bottom:14px;'
        f'font-size:12px;color:{C["text_muted"]}">'
        f'{_icon("layers", 14, C["brand"])}'
        f'<span><b style="color:{C["text"]}">{total_fw_hit}</b> of {len(_ALL_FRAMEWORKS)} '
        f'frameworks have triggered violations</span>'
        f'</div>'
        f'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:12px">'
        f'{cards}'
        f'</div>'
        f'</div>'
    )


def _framework_badges(finding_id: str) -> str:
    """Return HTML framework badge chips for a given finding ID."""
    fw = _load_frameworks()
    refs = fw["findings"].get(finding_id, [])
    if not refs:
        return ""
    colors = fw["colors"]
    badges = ""
    for ref in refs:
        name = ref.get("framework", "")
        rid  = ref.get("id", "")
        rname = ref.get("name", "")
        url  = ref.get("url", "#")
        col  = colors.get(name, {})
        bg   = col.get("bg", C["bg_raised"])
        fg   = col.get("fg", C["text_muted"])
        tooltip = html.escape(f"{name} — {rid}: {rname}")
        badges += (
            f'<a href="{html.escape(url)}" target="_blank" rel="noopener" title="{tooltip}" '
            f'style="display:inline-flex;align-items:center;gap:3px;padding:1px 6px;'
            f'border-radius:4px;background:{bg};color:{fg};font-size:10px;font-weight:700;'
            f'text-decoration:none;border:1px solid {fg}30;white-space:nowrap;flex-shrink:0">'
            f'{html.escape(rid)}</a>'
        )
    return f'<div style="display:flex;flex-wrap:wrap;gap:4px;margin-top:6px">{badges}</div>'


# ── Score helpers ──────────────────────────────────────────────────────────────

def _module_score(result: EvaluatorResult | None) -> float:
    if result is None:
        return 50.0
    if result.status in (EvaluatorStatus.SKIPPED, EvaluatorStatus.ERROR):
        return 50.0
    penalty = (
        result.critical_count * 40 +
        result.high_count     * 20 +
        result.medium_count   * 10 +
        result.low_count      *  3
    )
    return max(0.0, 100.0 - penalty)


def _overall_score(report: SecurityReport) -> float:
    return sum([
        _module_score(report.provenance),
        _module_score(report.adversarial),
        _module_score(report.privacy),
        _module_score(report.file_security),
    ]) / 4


def _risk_meta(score: float) -> tuple[str, str, str]:
    """(label, fg_color, bg_color)"""
    if score >= 85: return "LOW RISK",      C["pass_"],   C["pass_bg"]
    if score >= 65: return "MEDIUM RISK",   C["medium"],  C["medium_bg"]
    if score >= 40: return "HIGH RISK",     C["high"],    C["high_bg"]
    return              "CRITICAL RISK",    C["critical"],C["critical_bg"]


# ── Inline SVG helpers ─────────────────────────────────────────────────────────

def _icon(name: str, size: int = 16, color: str = "currentColor") -> str:
    svg = ICONS.get(name, ICONS["info"])
    return (f'<span style="display:inline-flex;align-items:center;justify-content:center;'
            f'width:{size}px;height:{size}px;flex-shrink:0;color:{color}">{svg}</span>')


def _arc(cx: float, cy: float, r: float, start_deg: float, end_deg: float) -> str:
    s, e = math.radians(start_deg), math.radians(end_deg)
    x1, y1 = cx + r * math.cos(s), cy - r * math.sin(s)
    x2, y2 = cx + r * math.cos(e), cy - r * math.sin(e)
    lg = 1 if abs(end_deg - start_deg) > 180 else 0
    return f"M {x1:.2f} {y1:.2f} A {r} {r} 0 {lg} 0 {x2:.2f} {y2:.2f}"


def _gauge_svg(score: float, size: int = 220) -> str:
    """Full-circle progress ring with score, label, and per-band breakdown bars."""
    label, fg, bg = _risk_meta(score)
    cx = cy = size / 2
    r_outer = size * 0.36
    r_inner = size * 0.26
    stroke_w = r_outer - r_inner          # ring thickness
    r_mid    = (r_outer + r_inner) / 2
    circ     = 2 * math.pi * r_mid

    # Full-circle progress: rotate so 0 is at top (-90°)
    filled   = (score / 100) * circ
    gap      = circ - filled

    # Segment background arcs for each risk band (coloured track)
    bands = [
        (40,  C["critical"] + "28"),   # 0–40  critical band
        (25,  C["high"]     + "28"),   # 40–65 high band
        (20,  C["medium"]   + "28"),   # 65–85 medium band
        (15,  C["pass_"]    + "28"),   # 85–100 pass band
    ]
    band_arcs = ""
    band_start = 0.0
    for band_pct, band_color in bands:
        bs = band_start / 100 * circ
        be = (band_start + band_pct) / 100 * circ
        band_dash = be - bs
        band_offset = circ - bs
        band_arcs += (
            f'<circle cx="{cx}" cy="{cy}" r="{r_mid:.2f}" fill="none"'
            f' stroke="{band_color}" stroke-width="{stroke_w:.1f}"'
            f' stroke-dasharray="{band_dash:.2f} {circ - band_dash:.2f}"'
            f' stroke-dashoffset="{band_offset:.2f}"'
            f' transform="rotate(-90 {cx} {cy})"/>'
        )
        band_start += band_pct

    # Score arc on top
    score_arc = (
        f'<circle cx="{cx}" cy="{cy}" r="{r_mid:.2f}" fill="none"'
        f' stroke="{fg}" stroke-width="{stroke_w:.1f}" stroke-linecap="round"'
        f' stroke-dasharray="{filled:.2f} {gap:.2f}"'
        f' stroke-dashoffset="{circ:.2f}"'
        f' transform="rotate(-90 {cx} {cy})"/>'
    ) if score > 0.5 else ""

    # Inner circle fill
    inner_fill = f'<circle cx="{cx}" cy="{cy}" r="{r_inner - 2:.1f}" fill="{bg}" opacity="0.5"/>'

    # Score text (large)
    score_text = (
        f'<text x="{cx}" y="{cy - size*0.04:.1f}" text-anchor="middle"'
        f' dominant-baseline="auto" fill="{fg}"'
        f' font-size="{size*0.20:.0f}" font-weight="800"'
        f' font-family="system-ui,sans-serif">{score:.0f}</text>'
    )
    sub_text = (
        f'<text x="{cx}" y="{cy + size*0.07:.1f}" text-anchor="middle"'
        f' dominant-baseline="auto" fill="{C["text_muted"]}"'
        f' font-size="{size*0.058:.0f}"'
        f' font-family="system-ui,sans-serif">/ 100</text>'
    )
    label_text = (
        f'<text x="{cx}" y="{cy + size*0.16:.1f}" text-anchor="middle"'
        f' dominant-baseline="auto" fill="{fg}"'
        f' font-size="{size*0.062:.0f}" font-weight="700"'
        f' font-family="system-ui,sans-serif" letter-spacing="0.5">{label}</text>'
    )

    return (
        f'<svg viewBox="0 0 {size} {size}" xmlns="http://www.w3.org/2000/svg"'
        f' style="width:100%;max-width:{size}px;display:block;margin:0 auto">'
        f'<circle cx="{cx}" cy="{cy}" r="{r_mid:.2f}" fill="none"'
        f' stroke="{C["border"]}" stroke-width="{stroke_w:.1f}"/>'
        f'{band_arcs}'
        f'{score_arc}'
        f'{inner_fill}'
        f'{score_text}'
        f'{sub_text}'
        f'{label_text}'
        f'</svg>'
    )


def _radar_svg(scores: dict[str, float], size: int = 270) -> str:
    cx, cy = size / 2, size / 2
    r_max  = size * 0.33
    labels = list(scores.keys())
    values = list(scores.values())
    n      = len(labels)
    angles = [math.pi / 2 + 2 * math.pi * i / n for i in range(n)]

    def pt(a: float, v: float) -> tuple[float, float]:
        f = v / 100
        return cx + r_max * f * math.cos(a), cy - r_max * f * math.sin(a)

    rings = ""
    for pct in [20, 40, 60, 80, 100]:
        pts = " ".join(
            f"{cx + r_max*(pct/100)*math.cos(a):.1f},{cy - r_max*(pct/100)*math.sin(a):.1f}"
            for a in angles
        )
        rings += (
            f'<polygon points="{pts}" fill="none" '
            f'stroke="{C["border"]}" stroke-width="1" opacity="0.8"/>'
        )
        ly = cy - r_max * (pct / 100) * math.sin(angles[0]) - 5
        lx = cx + r_max * (pct / 100) * math.cos(angles[0])
        rings += (
            f'<text x="{lx:.1f}" y="{ly:.1f}" text-anchor="middle" '
            f'fill="{C["text_light"]}" font-size="8" font-family="system-ui,sans-serif">{pct}</text>'
        )

    spokes = "".join(
        f'<line x1="{cx:.1f}" y1="{cy:.1f}" '
        f'x2="{cx + r_max*math.cos(a):.1f}" y2="{cy - r_max*math.sin(a):.1f}" '
        f'stroke="{C["border"]}" stroke-width="1" opacity="0.8"/>'
        for a in angles
    )

    avg_score = sum(values) / len(values)
    _, fill_fg, fill_bg = _risk_meta(avg_score)

    val_pts = " ".join(f"{pt(a,v)[0]:.2f},{pt(a,v)[1]:.2f}" for a, v in zip(angles, values))

    dots = ""
    label_pad = size * 0.115
    axis_labels = ""
    for i, (a, v, lbl) in enumerate(zip(angles, values, labels)):
        px, py = pt(a, v)
        _, dc, _ = _risk_meta(v)
        dots += (
            f'<circle cx="{px:.2f}" cy="{py:.2f}" r="5" '
            f'fill="{dc}" stroke="white" stroke-width="2"/>'
        )
        lx = cx + (r_max + label_pad) * math.cos(a)
        ly = cy - (r_max + label_pad) * math.sin(a)
        anchor = "middle"
        if lx < cx - 8:   anchor = "end"
        elif lx > cx + 8: anchor = "start"
        words, lines, cur = lbl.split(" "), [], ""
        for w in words:
            if len(cur) + len(w) + 1 > 13 and cur:
                lines.append(cur); cur = w
            else:
                cur = (cur + " " + w).strip()
        if cur: lines.append(cur)
        lh = 13
        by = ly - (len(lines) - 1) * lh / 2
        for li, line in enumerate(lines):
            axis_labels += (
                f'<text x="{lx:.1f}" y="{by + li*lh:.1f}" text-anchor="{anchor}" '
                f'dominant-baseline="middle" fill="{C["text"]}" font-size="11" '
                f'font-weight="600" font-family="system-ui,sans-serif">'
                f'{html.escape(line)}</text>'
            )

    pad = 52  # room for axis labels that extend beyond the polygon
    vw  = size + 2 * pad
    vh  = size + 2 * pad
    # shift all geometry by +pad so the centre is at (cx+pad, cy+pad)
    return f'''<svg viewBox="0 0 {vw} {vh}" xmlns="http://www.w3.org/2000/svg"
  style="width:100%;max-width:{vw}px;display:block;margin:0 auto">
  <g transform="translate({pad},{pad})">
    <rect width="{size}" height="{size}" fill="transparent"/>
    {rings}
    {spokes}
    <polygon points="{val_pts}" fill="{fill_bg}" stroke="{fill_fg}"
      stroke-width="2.5" stroke-linejoin="round" opacity="0.85"/>
    {dots}
    {axis_labels}
  </g>
</svg>'''


def _donut_svg(counts: dict[str, int], size: int = 200) -> str:
    slices = [
        ("critical", "Critical", C["critical"]),
        ("high",     "High",     C["high"]),
        ("medium",   "Medium",   C["medium"]),
        ("low",      "Low",      C["low"]),
        ("info",     "Info",     C["info"]),
    ]
    data  = [(lbl, clr, counts.get(k, 0)) for k, lbl, clr in slices if counts.get(k, 0) > 0]
    total = sum(v for _, _, v in data)
    cx = cy = size / 2
    ro, ri  = size * 0.40, size * 0.25

    if total == 0:
        return f'''<svg viewBox="0 0 {size} {size}" xmlns="http://www.w3.org/2000/svg"
  style="width:100%;max-width:{size}px;display:block;margin:0 auto">
  <circle cx="{cx}" cy="{cy}" r="{ro}" fill="none"
    stroke="{C["border"]}" stroke-width="{ro-ri}"/>
  <text x="{cx}" y="{cy-7}" text-anchor="middle" fill="{C["pass_"]}"
    font-size="15" font-weight="800" font-family="system-ui,sans-serif">No</text>
  <text x="{cx}" y="{cy+11}" text-anchor="middle" fill="{C["pass_"]}"
    font-size="15" font-weight="800" font-family="system-ui,sans-serif">Findings</text>
</svg>'''

    def wedge(sd: float, ed: float, clr: str) -> str:
        s, e = math.radians(sd - 90), math.radians(ed - 90)
        ox, oy   = cx + ro * math.sin(s), cy - ro * math.cos(s)
        ix, iy   = cx + ri * math.sin(s), cy - ri * math.cos(s)
        exo, eyo = cx + ro * math.sin(e), cy - ro * math.cos(e)
        exi, eyi = cx + ri * math.sin(e), cy - ri * math.cos(e)
        lg = 1 if (ed - sd) > 180 else 0
        return (
            f'<path d="M {ox:.2f} {oy:.2f} A {ro} {ro} 0 {lg} 1 {exo:.2f} {eyo:.2f} '
            f'L {exi:.2f} {eyi:.2f} A {ri} {ri} 0 {lg} 0 {ix:.2f} {iy:.2f} Z" '
            f'fill="{clr}" stroke="white" stroke-width="2"/>'
        )

    svg_wedges, cur = "", 0.0
    for _, clr, val in data:
        deg = (val / total) * 360
        if deg > 0.5:
            svg_wedges += wedge(cur, cur + deg - 0.3, clr)
        cur += deg

    legend = "".join(
        f'<span style="display:inline-flex;align-items:center;gap:5px;'
        f'font-size:11px;color:{C["text_muted"]};margin:0 5px">'
        f'<span style="width:9px;height:9px;border-radius:50%;'
        f'background:{clr};flex-shrink:0"></span>{val}&nbsp;{lbl}</span>'
        for lbl, clr, val in data
    )

    return f'''<div style="text-align:center">
<svg viewBox="0 0 {size} {size}" xmlns="http://www.w3.org/2000/svg"
  style="width:100%;max-width:{size}px;display:block;margin:0 auto">
  {svg_wedges}
  <text x="{cx}" y="{cy-7}" text-anchor="middle" fill="{C["text"]}"
    font-size="20" font-weight="800" font-family="system-ui,sans-serif">{total}</text>
  <text x="{cx}" y="{cy+11}" text-anchor="middle" fill="{C["text_muted"]}"
    font-size="10" font-family="system-ui,sans-serif">findings</text>
</svg>
<div style="display:flex;flex-wrap:wrap;justify-content:center;margin-top:6px">{legend}</div>
</div>'''


def _score_ring(score: float, size: int = 68) -> str:
    r    = size * 0.40
    circ = 2 * math.pi * r
    dash = (score / 100) * circ
    gap  = circ - dash
    _, fg, _ = _risk_meta(score)
    cx = cy  = size / 2
    return (
        f'<svg viewBox="0 0 {size} {size}" style="width:{size}px;height:{size}px;flex-shrink:0">'
        f'<circle cx="{cx}" cy="{cy}" r="{r}" fill="none" stroke="{C["border"]}" stroke-width="6"/>'
        f'<circle cx="{cx}" cy="{cy}" r="{r}" fill="none" stroke="{fg}" stroke-width="6" '
        f'stroke-linecap="round" stroke-dasharray="{dash:.2f} {gap:.2f}" '
        f'transform="rotate(-90 {cx} {cy})"/>'
        f'<text x="{cx}" y="{cy+1}" text-anchor="middle" dominant-baseline="middle" '
        f'fill="{fg}" font-size="{size*0.21:.0f}" font-weight="800" '
        f'font-family="system-ui,sans-serif">{score:.0f}</text>'
        f'</svg>'
    )


# ── HTML component builders ────────────────────────────────────────────────────

def _sev_badge(sev: Severity) -> str:
    fg, bg = SEV_COLOR[sev]
    iname  = {
        Severity.CRITICAL: "shield_x",
        Severity.HIGH:     "alert",
        Severity.MEDIUM:   "alert",
        Severity.LOW:      "info",
        Severity.INFO:     "info",
    }.get(sev, "info")
    return (
        f'<span style="display:inline-flex;align-items:center;gap:4px;'
        f'padding:2px 8px 2px 6px;border-radius:12px;background:{bg};'
        f'color:{fg};font-size:11px;font-weight:700;white-space:nowrap;'
        f'border:1px solid {fg}30">'
        f'{_icon(iname, 12, fg)}<span>{sev.value.upper()}</span></span>'
    )


def _status_badge(status: EvaluatorStatus) -> str:
    fg, bg, iname, label = STATUS_META.get(
        status, (C["skip"], C["skip_bg"], "info", status.value.upper()))
    return (
        f'<span style="display:inline-flex;align-items:center;gap:5px;'
        f'padding:4px 12px;border-radius:20px;background:{bg};'
        f'border:1px solid {fg}30;color:{fg};font-size:12px;font-weight:700">'
        f'{_icon(iname, 14, fg)}<span>{label}</span></span>'
    )


def _finding_card(finding: Finding) -> str:
    fg, bg = SEV_COLOR[finding.severity]
    iname  = {
        Severity.CRITICAL: "shield_x",
        Severity.HIGH:     "alert",
        Severity.MEDIUM:   "alert",
        Severity.LOW:      "info",
        Severity.INFO:     "info",
    }.get(finding.severity, "info")

    desc = html.escape(finding.description[:480] + ("…" if len(finding.description) > 480 else ""))

    remed = ""
    if finding.remediation:
        remed = (
            f'<div style="margin-top:10px;padding:10px 12px;background:{C["bg_accent"]};'
            f'border-left:3px solid {C["accent"]};border-radius:0 6px 6px 0">'
            f'<div style="display:flex;align-items:flex-start;gap:7px">'
            f'{_icon("wrench", 13, C["accent"])}'
            f'<div style="font-size:12px;color:{C["text_muted"]};line-height:1.6">'
            f'<span style="color:{C["accent"]};font-weight:600">Remediation: </span>'
            f'{html.escape(finding.remediation)}</div></div></div>'
        )

    refs = ""
    if finding.references:
        refs = '<div style="margin-top:8px;display:flex;flex-wrap:wrap;gap:6px">'
        for ref in finding.references:
            disp = ref.replace("https://","").replace("http://","")
            if len(disp) > 50: disp = disp[:47] + "…"
            refs += (
                f'<a href="{html.escape(ref)}" target="_blank" rel="noopener" '
                f'style="display:inline-flex;align-items:center;gap:4px;font-size:10px;'
                f'color:{C["accent"]};text-decoration:none;padding:2px 7px;'
                f'border:1px solid {C["border"]};border-radius:4px;'
                f'background:{C["bg_raised"]}">'
                f'{_icon("link", 10, C["accent"])}{html.escape(disp)}</a>'
            )
        refs += "</div>"

    fw_badges = _framework_badges(finding.id)

    return f'''<details style="background:{C["bg_card"]};border:1px solid {C["border"]};
  border-left:4px solid {fg};border-radius:0 6px 6px 0;margin-bottom:6px;
  box-shadow:0 1px 3px #0000000a">
  <summary style="list-style:none;padding:11px 14px;cursor:pointer;
    display:flex;align-items:center;gap:10px;user-select:none">
    <span style="display:flex;align-items:center;justify-content:center;
      width:30px;height:30px;border-radius:50%;background:{bg};flex-shrink:0">
      {_icon(iname, 16, fg)}
    </span>
    <div style="flex:1;min-width:0;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
      <code style="font-size:11px;font-weight:700;color:{C["text_muted"]};
        background:{C["bg_raised"]};padding:1px 6px;border-radius:4px;
        border:1px solid {C["border"]};white-space:nowrap">{html.escape(finding.id)}</code>
      {_sev_badge(finding.severity)}
      <span style="font-size:13px;font-weight:600;color:{C["text"]};
        flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;min-width:0">
        {html.escape(finding.title)}</span>
    </div>
    <span style="color:{C["text_light"]};flex-shrink:0;transition:transform .2s" class="chev">
      {_icon("chevron", 16)}
    </span>
  </summary>
  <div style="padding:2px 14px 14px 54px;border-top:1px solid {C["border_light"]}">
    <p style="margin:10px 0 0;font-size:13px;color:{C["text_muted"]};
      line-height:1.65;white-space:pre-wrap">{desc}</p>
    {remed}
    {refs}
    {fw_badges}
  </div>
</details>'''


def _passed_checks_block(passed: list[PassedCheck]) -> str:
    """Render a collapsible 'Passed Checks' green row after findings."""
    if not passed:
        return ""
    rows = "".join(
        f'<div style="display:flex;align-items:flex-start;gap:10px;'
        f'padding:7px 0;border-bottom:1px solid {C["border_light"]}">'
        f'<span style="display:inline-flex;align-items:center;justify-content:center;'
        f'width:20px;height:20px;border-radius:50%;background:{C["pass_bg"]};flex-shrink:0;margin-top:1px">'
        f'{_icon("check", 11, C["pass_"])}</span>'
        f'<div style="min-width:0;flex:1">'
        f'<span style="font-size:13px;font-weight:600;color:{C["text"]}">'
        f'{html.escape(pc.id)}</span>'
        f'<span style="font-size:13px;color:{C["text_muted"]};margin-left:8px">'
        f'{html.escape(pc.title)}</span>'
        + (f'<span style="font-size:11px;color:{C["text_light"]};margin-left:8px">'
           f'— {html.escape(pc.detail)}</span>' if pc.detail else "")
        + f'</div></div>'
        for pc in passed
    )
    return (
        f'<details style="margin-top:10px;border-radius:8px;overflow:hidden;'
        f'border:1px solid {C["pass_"]}33">'
        f'<summary style="list-style:none;cursor:pointer;user-select:none;'
        f'padding:10px 14px;background:{C["pass_bg"]};'
        f'display:flex;align-items:center;gap:8px;font-size:13px;font-weight:600;'
        f'color:{C["pass_"]}">'
        f'{_icon("check", 15, C["pass_"])}'
        f'<span>{len(passed)} check{"s" if len(passed) != 1 else ""} passed</span>'
        f'</summary>'
        f'<div style="padding:8px 14px 4px;background:{C["bg_card"]}">{rows}</div>'
        f'</details>'
    )


def _module_section(result: EvaluatorResult, icon_name: str, help_key: str = "") -> str:
    fg, bg, _, _ = STATUS_META.get(result.status, (C["skip"], C["skip_bg"], "info", "SKIP"))
    SEV_ORDER = {Severity.CRITICAL:0, Severity.HIGH:1, Severity.MEDIUM:2,
                 Severity.LOW:3, Severity.INFO:4, Severity.UNKNOWN:5}
    sorted_findings = sorted(result.findings, key=lambda f: SEV_ORDER.get(f.severity, 9))

    counts_html = ""
    for sev, label, color in [
        (Severity.CRITICAL, "Critical", C["critical"]),
        (Severity.HIGH,     "High",     C["high"]),
        (Severity.MEDIUM,   "Medium",   C["medium"]),
        (Severity.LOW,      "Low",      C["low"]),
    ]:
        n   = sum(1 for f in result.findings if f.severity == sev)
        op  = "1" if n > 0 else "0.3"
        counts_html += (
            f'<span style="display:inline-flex;align-items:center;gap:4px;'
            f'font-size:12px;color:{color};opacity:{op};font-weight:600">'
            f'{n} <span style="font-weight:400;color:{C["text_muted"]}">{label}</span></span>'
        )

    passed_block = _passed_checks_block(result.passed_checks)

    body = ""
    if not sorted_findings:
        body = (
            f'<div style="padding:20px;text-align:center;color:{C["pass_"]};'
            f'font-size:13px;display:flex;align-items:center;justify-content:center;gap:8px">'
            f'{_icon("check", 17, C["pass_"])}'
            f'<span style="font-weight:600">No findings — this module is clean.</span></div>'
            + passed_block
        )
    else:
        body = "".join(_finding_card(f) for f in sorted_findings) + passed_block

    return f'''<section style="margin-bottom:20px">
  <details open>
    <summary style="list-style:none;cursor:pointer;user-select:none;
      display:flex;align-items:center;gap:12px;padding:14px 18px;
      background:{C["bg_card"]};border:1px solid {C["border"]};
      border-radius:10px 10px 0 0;border-bottom:none;
      box-shadow:0 1px 3px #0000000a">
      <span style="display:flex;align-items:center;justify-content:center;
        width:38px;height:38px;border-radius:9px;background:{C["bg_accent"]};flex-shrink:0">
        {_icon(icon_name, 20, C["brand"])}
      </span>
      <div style="flex:1;min-width:0">
        <div style="font-size:15px;font-weight:700;color:{C["text"]};display:flex;align-items:center;gap:7px">
          {html.escape(result.name)}{_help_btn(help_key) if help_key else ""}</div>
        <div style="font-size:12px;color:{C["text_muted"]};margin-top:2px;
          overflow:hidden;text-overflow:ellipsis;white-space:nowrap">{html.escape(result.summary)}</div>
      </div>
      <div style="display:flex;align-items:center;gap:14px;flex-wrap:wrap">
        <div style="display:flex;gap:12px">{counts_html}</div>
        {_status_badge(result.status)}
      </div>
    </summary>
    <div style="background:{C["bg"]};border:1px solid {C["border"]};
      border-top:none;border-radius:0 0 10px 10px;padding:12px 12px 6px">
      {body}
    </div>
  </details>
</section>'''


def _provenance_grid(report: SecurityReport) -> str:
    meta = (report.provenance.metadata if report.provenance else {}) or {}

    def cell(iname: str, label: str, value: str, vc: str = "") -> str:
        color = vc or C["text"]
        return (
            f'<div style="background:{C["bg_card"]};border:1px solid {C["border"]};'
            f'border-radius:8px;padding:14px 16px;display:flex;align-items:flex-start;gap:12px;'
            f'box-shadow:0 1px 3px #0000000a">'
            f'<span style="display:flex;align-items:center;justify-content:center;'
            f'width:34px;height:34px;border-radius:8px;background:{C["bg_accent"]};'
            f'flex-shrink:0">{_icon(iname, 17, C["brand"])}</span>'
            f'<div style="min-width:0;flex:1">'
            f'<div style="font-size:10px;font-weight:700;color:{C["text_light"]};'
            f'text-transform:uppercase;letter-spacing:0.6px;margin-bottom:3px">{html.escape(label)}</div>'
            f'<div style="font-size:14px;font-weight:600;color:{color};'
            f'word-break:break-word;line-height:1.4">{html.escape(str(value))}</div>'
            f'</div></div>'
        )

    author    = meta.get("author",           "Unknown")
    country   = meta.get("country_of_origin","Unknown")
    license_  = meta.get("license",          "Unknown")
    pipeline  = meta.get("pipeline_tag",     "Unknown")
    downloads = f'{meta.get("downloads", 0):,}'
    likes     = f'{meta.get("likes", 0):,}'
    modified  = str(meta.get("last_modified","Unknown"))[:10]
    gated     = str(meta.get("gated","false")).lower()
    datasets  = ", ".join(meta.get("datasets",[])[:4]) or "Not disclosed"

    c_color  = C["text"]    if country  != "Unknown"                    else C["warn"]
    l_color  = C["pass_"]   if license_ not in ("Unknown","","other")   else C["warn"]
    g_color  = C["warn"]    if gated    not in ("false","")             else C["pass_"]

    return (
        f'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(185px,1fr));'
        f'gap:10px;margin-bottom:28px">'
        + cell("user",     "Author",           author)
        + cell("map_pin",  "Country of Origin", country,  c_color)
        + cell("book",     "License",           license_, l_color)
        + cell("cpu",      "Pipeline",          pipeline)
        + cell("download", "Downloads",         downloads)
        + cell("heart",    "Likes",             likes)
        + cell("calendar", "Last Modified",     modified)
        + cell("tag",      "Gated Access",      gated,    g_color)
        + cell("database", "Training Datasets", datasets)
        + '</div>'
    )


def _module_score_cards(report: SecurityReport) -> str:
    modules = [
        ("Supply Chain & Provenance",  report.provenance,    "globe"),
        ("Adversarial Robustness",     report.adversarial,   "sword"),
        ("Data & Privacy Risks",       report.privacy,       "lock"),
        ("Model File Security",        report.file_security, "file"),
    ]
    cards = ""
    for name, result, iname in modules:
        score  = _module_score(result)
        _, fg, bg = _risk_meta(score)
        status = result.status if result else EvaluatorStatus.SKIPPED

        n_c = result.critical_count if result else 0
        n_h = result.high_count     if result else 0
        n_m = result.medium_count   if result else 0
        n_l = result.low_count      if result else 0

        mini = ""
        for letter, count, color, cbg in [
            ("C", n_c, C["critical"], C["critical_bg"]),
            ("H", n_h, C["high"],     C["high_bg"]),
            ("M", n_m, C["medium"],   C["medium_bg"]),
            ("L", n_l, C["low"],      C["low_bg"]),
        ]:
            op  = "1" if count > 0 else "0.3"
            mini += (
                f'<div style="text-align:center;padding:6px 4px;'
                f'background:{cbg};border-radius:6px;opacity:{op};border:1px solid {color}20">'
                f'<div style="font-size:9px;font-weight:700;color:{color};'
                f'text-transform:uppercase;margin-bottom:2px">{letter}</div>'
                f'<div style="font-size:16px;font-weight:800;color:{color};line-height:1">{count}</div>'
                f'</div>'
            )

        cards += (
            f'<div style="background:{C["bg_card"]};border:1px solid {C["border"]};'
            f'border-top:4px solid {fg};border-radius:10px;padding:18px;'
            f'display:flex;flex-direction:column;gap:10px;'
            f'box-shadow:0 2px 6px #0000000d">'
            f'<div style="display:flex;align-items:center;gap:10px">'
            f'<span style="display:flex;align-items:center;justify-content:center;'
            f'width:38px;height:38px;border-radius:9px;background:{C["bg_accent"]};flex-shrink:0">'
            f'{_icon(iname, 20, C["brand"])}</span>'
            f'<div style="font-size:13px;font-weight:700;color:{C["text"]};line-height:1.3">'
            f'{html.escape(name)}</div></div>'
            f'<div style="display:flex;align-items:center;gap:14px">'
            f'{_score_ring(score, 66)}'
            f'<div>'
            f'<div style="font-size:30px;font-weight:800;color:{fg};line-height:1">{score:.0f}</div>'
            f'<div style="font-size:10px;color:{C["text_muted"]};margin-bottom:6px">/ 100</div>'
            f'{_status_badge(status)}'
            f'</div></div>'
            f'<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:6px">{mini}</div>'
            f'</div>'
        )
    return (
        f'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(210px,1fr));'
        f'gap:14px;margin-bottom:28px">{cards}</div>'
    )


