def _help_js_data() -> str:
    """Emit JS lines that populate the HELP object from the Python HELP dict."""
    import json
    lines = []
    for key, (title, body) in HELP.items():
        lines.append(f'HELP[{json.dumps(key)}] = [{json.dumps(title)}, {json.dumps(body)}];')
    return "\n".join(lines)


# ── Recommendations engine ────────────────────────────────────────────────────

_REC_CATALOGUE: list[dict] | None = None


def _load_rec_catalogue() -> list[dict]:
    """Load and cache the recommendations YAML catalogue."""
    global _REC_CATALOGUE
    if _REC_CATALOGUE is not None:
        return _REC_CATALOGUE
    try:
        import yaml
    except ImportError:
        print("WARNING: PyYAML not installed — recommendations catalogue unavailable.")
        _REC_CATALOGUE = []
        return _REC_CATALOGUE
    catalogue_path = Path(__file__).parent / "recommendations.yaml"
    try:
        with catalogue_path.open("r", encoding="utf-8") as fh:
            data = yaml.safe_load(fh) or {}
            _REC_CATALOGUE = data.get("recommendations", []) if isinstance(data, dict) else []
    except FileNotFoundError:
        print(f"WARNING: recommendations.yaml not found at {catalogue_path} — using empty catalogue.")
        _REC_CATALOGUE = []
    except Exception as exc:
        print(f"WARNING: Failed to load recommendations.yaml: {exc}")
        _REC_CATALOGUE = []
    return _REC_CATALOGUE


def _build_recommendations(report: SecurityReport, score: float) -> list[dict]:
    """
    Analyse findings and the overall score to produce a prioritised list of
    actionable recommendations, driven by the YAML catalogue.

    Each recommendation dict has:
        priority      : "critical" | "high" | "medium" | "low"
        category      : human-readable category label
        icon          : icon name from ICONS
        title         : short title
        description   : one-paragraph explanation
        actions       : list[str]  — ordered checklist steps
        triggered_by  : list[str]  — finding IDs that caused this entry
    """
    all_findings: list[Finding] = []
    for r in [report.provenance, report.adversarial,
              report.privacy, report.file_security]:
        if r:
            all_findings.extend(r.findings)

    # Severity ordering for min-sev checks (higher index = higher severity)
    _SEV_ORDER = {
        "info": 0, "low": 1, "medium": 2, "high": 3, "critical": 4,
    }

    def _sev_str(sev) -> str:
        """Normalise a Severity enum or string to lowercase string."""
        if hasattr(sev, "value"):
            return sev.value.lower()
        return str(sev).lower()

    def _sev_meets_min(finding_sev, min_sev_str: str) -> bool:
        actual = _SEV_ORDER.get(_sev_str(finding_sev), 0)
        minimum = _SEV_ORDER.get(min_sev_str.lower(), 0)
        return actual >= minimum

    catalogue = _load_rec_catalogue()

    recs: list[dict] = []
    triggered_ids: set[str] = set()  # catalogue entry ids that fired

    for entry in catalogue:
        rec_id = entry.get("id", "")
        triggers = entry.get("triggers", {})

        matched_by: list[str] = []

        # finding_ids: any finding.id in the list
        for fid in triggers.get("finding_ids", []):
            for f in all_findings:
                if f.id == fid:
                    matched_by.append(f.id)
                    break

        # finding_prefixes: any finding.id starting with any prefix
        for prefix in triggers.get("finding_prefixes", []):
            for f in all_findings:
                if f.id.startswith(prefix):
                    matched_by.append(f.id)

        # finding_id_sev: finding.id present AND severity meets minimum
        for fid, min_sev in (triggers.get("finding_id_sev") or {}).items():
            for f in all_findings:
                if f.id == fid and _sev_meets_min(f.severity, min_sev):
                    matched_by.append(f.id)
                    break

        # score_below: score < value
        score_below = triggers.get("score_below")
        if score_below is not None and score < score_below:
            matched_by.append("overall-score")

        if not matched_by:
            continue

        # REC-SANDBOX must not fire if REC-BLOCK already fired
        if rec_id == "REC-SANDBOX" and "REC-BLOCK" in triggered_ids:
            continue

        triggered_ids.add(rec_id)
        recs.append(dict(
            id=rec_id,
            priority=entry.get("priority", "medium"),
            category=entry.get("category", ""),
            icon=entry.get("icon", "shield"),
            title=entry.get("title", ""),
            description=entry.get("description", ""),
            actions=entry.get("actions", []),
            triggered_by=list(dict.fromkeys(matched_by)),  # deduplicated, order-preserving
        ))

    # Sort: critical → high → medium → low
    _order = {"critical": 0, "high": 1, "medium": 2, "low": 3}
    recs.sort(key=lambda r: _order.get(r["priority"], 9))
    return recs


def _recommendations_section(recs: list[dict]) -> str:
    """Render the recommendations section HTML."""
    if not recs:
        return (
            f'<div style="padding:20px;text-align:center;color:{C["pass_"]};'
            f'font-size:13px;display:flex;align-items:center;justify-content:center;gap:8px;'
            f'background:{C["bg_card"]};border:1px solid {C["border"]};border-radius:10px;'
            f'margin-bottom:28px">'
            f'{_icon("check", 18, C["pass_"])}'
            f'<span style="font-weight:600">No recommendations — all checks passed.</span></div>'
        )

    _prio_meta = {
        "critical": (C["critical"], C["critical_bg"], "CRITICAL"),
        "high":     (C["high"],     C["high_bg"],     "HIGH"),
        "medium":   (C["medium"],   C["medium_bg"],   "MEDIUM"),
        "low":      (C["low"],      C["low_bg"],       "LOW"),
    }

    cards_html = ""
    for i, rec in enumerate(recs):
        fg, bg, label = _prio_meta.get(rec["priority"], (C["info"], C["info_bg"], "INFO"))

        # Action checklist
        actions_html = "".join(
            f'<li style="padding:5px 0;border-bottom:1px solid {C["border_light"]};'
            f'font-size:13px;color:{C["text"]};line-height:1.5">'
            f'<span style="display:inline-flex;align-items:flex-start;gap:9px">'
            f'<span style="display:inline-flex;align-items:center;justify-content:center;'
            f'min-width:20px;height:20px;border-radius:50%;background:{C["bg_accent"]};'
            f'border:1.5px solid {C["brand"]}30;font-size:9px;font-weight:800;'
            f'color:{C["brand"]};margin-top:1px">{j+1}</span>'
            f'<span>{html.escape(action)}</span>'
            f'</span></li>'
            for j, action in enumerate(rec["actions"])
        )

        # Triggered-by badge strip
        trigger_chips = "".join(
            f'<code style="font-size:10px;padding:1px 6px;border-radius:4px;'
            f'background:{C["bg_raised"]};border:1px solid {C["border"]};'
            f'color:{C["text_muted"]};font-family:monospace">'
            f'{html.escape(t)}</code>'
            for t in rec.get("triggered_by", []) if t != "overall-score"
        )

        cards_html += f'''
<div style="background:{C["bg_card"]};border:1px solid {C["border"]};
  border-left:4px solid {fg};border-radius:10px;
  margin-bottom:14px;overflow:hidden;box-shadow:0 2px 8px #0000000d">

  <!-- header row -->
  <div style="padding:16px 20px;display:flex;align-items:flex-start;gap:14px;
    border-bottom:1px solid {C["border_light"]}">
    <span style="display:flex;align-items:center;justify-content:center;
      width:40px;height:40px;border-radius:10px;background:{bg};flex-shrink:0;
      border:1px solid {fg}30">
      {_icon(rec["icon"], 20, fg)}
    </span>
    <div style="flex:1;min-width:0">
      <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:5px">
        <span style="font-size:10px;font-weight:800;text-transform:uppercase;
          letter-spacing:0.6px;padding:2px 9px;border-radius:10px;
          background:{bg};color:{fg};border:1px solid {fg}30">{label}</span>
        <span style="font-size:11px;font-weight:600;color:{C["text_muted"]}">
          {html.escape(rec["category"])}</span>
      </div>
      <div style="font-size:15px;font-weight:700;color:{C["text"]};line-height:1.4">
        {html.escape(rec["title"])}</div>
    </div>
    <span style="font-size:24px;font-weight:800;color:{fg}AA;
      flex-shrink:0;line-height:1;margin-top:2px">R{i+1}</span>
  </div>

  <!-- body -->
  <div style="padding:16px 20px">
    <p style="font-size:13px;color:{C["text_muted"]};margin-bottom:14px;line-height:1.6">
      {html.escape(rec["description"])}</p>
    <ol style="list-style:none;padding:0;margin:0 0 12px 0">
      {actions_html}
    </ol>
    {(
      f'<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;margin-top:10px">'
      f'<span style="font-size:10px;font-weight:700;color:{C["text_light"]};'
      f'text-transform:uppercase;letter-spacing:0.5px">Triggered by:</span>'
      f'{trigger_chips}'
      f'</div>'
    ) if trigger_chips else ""}
  </div>
</div>'''

    return cards_html


# ── AIBOM section ─────────────────────────────────────────────────────────────

def _aibom_section(report: SecurityReport, aibom: dict, model_idx: int | None = None) -> str:
    """
    Render the AIBOM summary card + download button for embedding in the
    HTML report.  The full JSON is embedded as a JS const so the download
    requires no server round-trip.
    """
    prov_meta  = (report.provenance  and report.provenance.metadata)  or {}
    file_meta  = (report.file_security and report.file_security.metadata) or {}
    counts     = report.total_findings()

    # ── field helpers ─────────────────────────────────────────────────────────
    def _row(label: str, value: str, color: str = "") -> str:
        vc = color or C["text"]
        return (
            f'<tr>'
            f'<td style="padding:7px 12px 7px 0;font-size:12px;font-weight:700;'
            f'color:{C["text_muted"]};text-transform:uppercase;letter-spacing:0.5px;'
            f'white-space:nowrap;vertical-align:top">{html.escape(label)}</td>'
            f'<td style="padding:7px 0;font-size:13px;color:{vc};'
            f'font-weight:600;word-break:break-word">{html.escape(str(value))}</td>'
            f'</tr>'
        )

    def _tag_chip(text: str, fg: str, bg: str) -> str:
        return (
            f'<span style="display:inline-block;padding:2px 9px;border-radius:10px;'
            f'background:{bg};color:{fg};font-size:11px;font-weight:700;'
            f'border:1px solid {fg}30;margin:2px 2px">{html.escape(text)}</span>'
        )

    # ── pull values ───────────────────────────────────────────────────────────
    author    = prov_meta.get("author",            "Unknown")
    license_  = prov_meta.get("license",           "Unknown")
    pipeline  = prov_meta.get("pipeline_tag",      "Unknown")
    country   = prov_meta.get("country_of_origin", "Unknown")
    created   = str(prov_meta.get("created_at",    "Unknown"))[:10]
    modified  = str(prov_meta.get("last_modified", "Unknown"))[:10]
    downloads = f'{prov_meta.get("downloads", 0):,}'
    arch_list = prov_meta.get("architectures", [])
    model_type = prov_meta.get("model_type", "Unknown")
    datasets  = prov_meta.get("datasets", [])
    tags      = prov_meta.get("tags", [])
    gated     = str(prov_meta.get("gated", "false")).lower()
    author_type = prov_meta.get("author_type", "unknown")

    file_formats = file_meta.get("file_formats", {})
    scanners     = file_meta.get("scanners_used", [])

    serial    = aibom.get("serialNumber", "")
    spec_ver  = aibom.get("specVersion",  "1.5")
    bom_ver   = aibom.get("version",      1)

    # ── severity chips ─────────────────────────────────────────────────────────
    sev_chips = "".join(
        _tag_chip(f"{counts.get(k,0)} {lbl}", fg, bg)
        for k, lbl, fg, bg in [
            ("critical", "Critical", C["critical"], C["critical_bg"]),
            ("high",     "High",     C["high"],     C["high_bg"]),
            ("medium",   "Medium",   C["medium"],   C["medium_bg"]),
            ("low",      "Low",      C["low"],      C["low_bg"]),
            ("info",     "Info",     C["info"],     C["info_bg"]),
        ]
    )

    # ── dataset chips ─────────────────────────────────────────────────────────
    ds_chips = (
        "".join(_tag_chip(d, C["brand"], C["accent_bg"]) for d in datasets[:8])
        + (f'<span style="font-size:11px;color:{C["text_muted"]}"> +{len(datasets)-8} more</span>'
           if len(datasets) > 8 else "")
    ) if datasets else f'<span style="font-size:12px;color:{C["text_muted"]}">Not disclosed</span>'

    # ── tag chips ─────────────────────────────────────────────────────────────
    tag_chips = (
        "".join(_tag_chip(t, C["text_muted"], C["bg_raised"]) for t in tags[:10])
    ) if tags else ""

    # ── file format table ─────────────────────────────────────────────────────
    fmt_cells = ""
    for fmt_name, fmt_key, fmt_color in [
        ("SafeTensors", "safetensors", C["pass_"]),
        ("Pickle",      "pickle_based", C["warn"]),
        ("GGUF",        "gguf",         C["brand"]),
        ("Other",       "other",        C["text_muted"]),
    ]:
        n = file_formats.get(fmt_key, 0) if file_formats else "—"
        fg = fmt_color if (isinstance(n, int) and n > 0) else C["text_light"]
        fmt_cells += (
            f'<div style="text-align:center;padding:8px 6px;background:{C["bg_raised"]};'
            f'border-radius:7px;border:1px solid {C["border_light"]}">'
            f'<div style="font-size:18px;font-weight:800;color:{fg}">{n}</div>'
            f'<div style="font-size:10px;color:{C["text_muted"]};font-weight:600;'
            f'text-transform:uppercase;letter-spacing:0.4px">{fmt_name}</div>'
            f'</div>'
        )

    # ── left column: BOM identity ─────────────────────────────────────────────
    left_rows = (
        _row("BOM Format",   f"CycloneDX {spec_ver}")
        + _row("BOM Version", str(bom_ver))
        + _row("Serial No.",  serial)
        + _row("Generated",   aibom["metadata"]["timestamp"][:19].replace("T", " ") + " UTC")
        + _row("Tool",        f"modelcheck v{report.tool_version}")
    )

    # ── right column: model identity ─────────────────────────────────────────
    right_rows = (
        _row("Component",     report.model_id)
        + _row("Type",        "machine-learning-model")
        + _row("Author",      author)
        + _row("Author Kind", author_type)
        + _row("License",     license_,
               C["pass_"] if license_ not in ("Unknown","unknown","") else C["warn"])
        + _row("Pipeline",    pipeline)
        + _row("Model Type",  model_type)
        + _row("Architecture",", ".join(arch_list) if arch_list else "Unknown")
        + _row("Country",     country)
        + _row("Created",     created)
        + _row("Modified",    modified)
        + _row("Downloads",   downloads)
        + _row("Gated",       gated)
        + _row("Source",      report.model_source.value.upper())
        + _row("Scanners",    ", ".join(scanners) if scanners else "metadata-only")
    )

    # ── section body ─────────────────────────────────────────────────────────
    body = f'''
<div style="background:{C["bg_card"]};border:1px solid {C["border"]};
  border-radius:12px;padding:24px;margin-bottom:14px;
  box-shadow:0 2px 8px #0000000d">

  <!-- top bar: title + download -->
  <div style="display:flex;align-items:center;justify-content:space-between;
    flex-wrap:wrap;gap:12px;margin-bottom:20px">
    <div style="display:flex;align-items:center;gap:10px">
      <span style="display:flex;align-items:center;justify-content:center;
        width:38px;height:38px;border-radius:9px;background:{C["accent_bg"]};
        border:1px solid {C["brand"]}20">
        {_icon("list", 20, C["brand"])}
      </span>
      <div>
        <div style="font-size:15px;font-weight:800;color:{C["text"]}">
          AI Bill of Materials</div>
        <div style="font-size:11px;color:{C["text_muted"]}">
          CycloneDX {spec_ver} &middot; machine-learning-model</div>
      </div>
    </div>
    <div style="display:flex;gap:8px;flex-wrap:wrap">
      <button id="aibom-dl-btn"
        style="display:inline-flex;align-items:center;gap:7px;
          padding:8px 18px;border-radius:7px;cursor:pointer;
          background:{C["brand"]};border:none;color:#FFFFFF;
          font-size:13px;font-weight:700;box-shadow:0 2px 6px {C["brand"]}40;
          transition:opacity 0.15s"
        onmouseover="this.style.opacity=0.88"
        onmouseout="this.style.opacity=1"
        onclick="downloadAibom({model_idx if model_idx is not None else ''})">
        {_icon("download", 14, "#FFFFFF")}
        Download AIBOM JSON
      </button>
    </div>
  </div>

  <!-- findings summary strip -->
  <div style="background:{C["bg_raised"]};border-radius:8px;padding:12px 14px;
    margin-bottom:18px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
    <span style="font-size:11px;font-weight:700;color:{C["text_muted"]};
      text-transform:uppercase;letter-spacing:0.5px;margin-right:4px">
      Findings:</span>
    {sev_chips}
    <span style="margin-left:auto;font-size:11px;color:{C["text_muted"]}">
      {counts.get("total", 0)} total vulnerabilities in BOM
    </span>
  </div>

  <!-- two-column metadata -->
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:18px">
    <!-- BOM identity -->
    <div style="background:{C["bg_raised"]};border-radius:8px;padding:14px 16px;
      border:1px solid {C["border_light"]}">
      <div style="font-size:11px;font-weight:700;color:{C["brand"]};
        text-transform:uppercase;letter-spacing:0.7px;margin-bottom:10px">
        BOM Identity</div>
      <table style="border-collapse:collapse;width:100%">
        {left_rows}
      </table>
    </div>
    <!-- Component identity -->
    <div style="background:{C["bg_raised"]};border-radius:8px;padding:14px 16px;
      border:1px solid {C["border_light"]}">
      <div style="font-size:11px;font-weight:700;color:{C["brand"]};
        text-transform:uppercase;letter-spacing:0.7px;margin-bottom:10px">
        Component Identity</div>
      <table style="border-collapse:collapse;width:100%">
        {right_rows}
      </table>
    </div>
  </div>

  <!-- file format grid (only shown if we have data) -->
  {(
    f'<div style="margin-bottom:18px">'
    f'<div style="font-size:11px;font-weight:700;color:{C["brand"]};'
    f'text-transform:uppercase;letter-spacing:0.7px;margin-bottom:8px">File Formats</div>'
    f'<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px">{fmt_cells}</div>'
    f'</div>'
  ) if file_formats else ""}

  <!-- datasets -->
  <div style="margin-bottom:18px">
    <div style="font-size:11px;font-weight:700;color:{C["brand"]};
      text-transform:uppercase;letter-spacing:0.7px;margin-bottom:8px">
      Training Datasets</div>
    <div>{ds_chips}</div>
  </div>

  <!-- model tags -->
  {(
    f'<div style="margin-bottom:18px">'
    f'<div style="font-size:11px;font-weight:700;color:{C["brand"]};'
    f'text-transform:uppercase;letter-spacing:0.7px;margin-bottom:8px">Model Tags</div>'
    f'<div>{tag_chips}</div>'
    f'</div>'
  ) if tags else ""}

  <!-- collapsible JSON preview -->
  <details style="border:1px solid {C["border_light"]};border-radius:8px;overflow:hidden">
    <summary style="padding:10px 14px;cursor:pointer;font-size:12px;font-weight:700;
      color:{C["text_muted"]};background:{C["bg_raised"]};
      list-style:none;display:flex;align-items:center;gap:8px;
      user-select:none">
      {_icon("code", 14, C["text_muted"])}
      <span>Preview AIBOM JSON</span>
      <svg class="chev" style="margin-left:auto;transition:transform 0.2s"
        width="14" height="14" viewBox="0 0 24 24" fill="none"
        stroke="currentColor" stroke-width="2.5" stroke-linecap="round">
        <polyline points="6 9 12 15 18 9"/>
      </svg>
    </summary>
    <div style="padding:14px;background:{C["bg"]}">
      <pre id="aibom-preview"
        style="margin:0;font-size:11px;line-height:1.6;
          color:{C["text"]};overflow-x:auto;white-space:pre;
          max-height:480px;overflow-y:auto"></pre>
    </div>
  </details>

</div>
'''
    return body


def _navbar(report: SecurityReport, score: float, recs: list[dict]) -> str:
    """Render the fixed left navigation sidebar."""
    prio_order = {"critical": 0, "high": 1, "medium": 2, "low": 3}
    top_prio = min((prio_order.get(r["priority"], 9) for r in recs), default=4)
    rec_color = (
        C["critical"] if top_prio == 0 else
        C["high"]     if top_prio == 1 else
        C["medium"]   if top_prio == 2 else
        C["low"]      if top_prio == 3 else C["pass_"]
    )
    rec_label = (
        "CRITICAL" if top_prio == 0 else
        "HIGH"     if top_prio == 1 else
        f"{len(recs)}" if recs else "\u2713"
    )

    _, score_fg, _ = _risk_meta(score)
    counts = report.total_findings()

    def status_dot(color: str, label: str = "") -> str:
        return (
            f'<span style="display:inline-flex;align-items:center;justify-content:center;'
            f'min-width:22px;height:18px;border-radius:9px;background:{color}22;'
            f'color:{color};font-size:9px;font-weight:800;letter-spacing:0.2px;'
            f'padding:0 5px;flex-shrink:0">{html.escape(label)}</span>'
        )

    def stat_fg(result) -> str:
        if result is None: return C["text_muted"]
        return {
            EvaluatorStatus.PASS:    C["pass_"],
            EvaluatorStatus.FAIL:    C["critical"],
            EvaluatorStatus.WARNING: C["high"],
            EvaluatorStatus.ERROR:   C["critical"],
            EvaluatorStatus.SKIPPED: C["text_muted"],
        }.get(result.status, C["text_muted"])

    def stat_lbl(result) -> str:
        if result is None: return "\u2013"
        return {
            EvaluatorStatus.PASS:    "\u2713",
            EvaluatorStatus.FAIL:    "\u2717",
            EvaluatorStatus.WARNING: "!",
            EvaluatorStatus.ERROR:   "\u2717",
            EvaluatorStatus.SKIPPED: "\u2013",
        }.get(result.status, "\u2013")

    items = [
        ("sec-provenance",      "globe",    "Provenance",       stat_fg(report.provenance),    stat_lbl(report.provenance)),
        ("sec-dashboard",       "activity", "Dashboard",        score_fg,                       f"{score:.0f}"),
        ("sec-module-scores",   "cpu",      "Module Scores",    score_fg,                       ""),
        ("sec-compliance",      "layers",   "Compliance",       C["brand"],                     ""),
        ("sec-findings",        "shield",   "Findings",         C["critical"] if counts.get("critical",0) else C["high"] if counts.get("high",0) else C["text_muted"], f'{counts["total"]}'),
        ("sec-aibom",           "list",     "AIBOM",            C["brand"],                     ""),
        ("sec-recommendations", "zap",      "Recommendations",  rec_color,                      rec_label),
    ]

    nav_items = ""
    for sec_id, icon_name, label, dot_color, dot_lbl in items:
        nav_items += (
            f'<li>'
            f'<a class="nav-item" href="#{sec_id}" onclick="expandSection(\'{sec_id}\')">'
            f'  <span class="nav-icon">{_icon(icon_name, 16, "currentColor")}</span>'
            f'  <span class="nav-label">{html.escape(label)}</span>'
            + (f'  {status_dot(dot_color, dot_lbl)}' if dot_lbl else "")
            + f'</a></li>'
        )

    return (
        f'<nav id="sidebar" aria-label="Report navigation">'
        f'<div class="nav-brand">'
        f'  <span class="nav-icon nav-brand-icon">{_icon("shield", 18, C["brand"])}</span>'
        f'  <span class="nav-label" style="font-weight:800;font-size:13px;color:#FFFFFF">Sections</span>'
        f'  <button id="nav-toggle" onclick="toggleSidebar()" '
        f'    aria-label="Toggle navigation" title="Collapse / expand sidebar">'
        f'    <svg id="nav-toggle-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" '
        f'      stroke="currentColor" stroke-width="2.5" stroke-linecap="round">'
        f'      <line x1="3" y1="12" x2="21" y2="12"/>'
        f'      <line x1="3" y1="6"  x2="21" y2="6"/>'
        f'      <line x1="3" y1="18" x2="21" y2="18"/>'
        f'    </svg>'
        f'  </button>'
        f'</div>'
        f'<ul class="nav-list">{nav_items}</ul>'
        f'<div class="nav-footer">'
        f'  <span class="nav-label" style="font-size:10px;color:#FFFFFF55">'
        f'    modelcheck v{html.escape(report.tool_version)}</span>'
        f'</div>'
        f'</nav>'
    )


def _collapsible_section(
    sec_id: str,
    icon_name: str,
    title: str,
    subtitle: str,
    help_key: str,
    body_html: str,
    badge_html: str = "",
) -> str:
    """Wraps a report section in a collapsible card with a clickable header."""
    hbtn = _help_btn(help_key) if help_key else ""
    sub_html = (
        f'<div style="font-size:11px;color:{C["text_muted"]};margin-top:1px">'
        f'{html.escape(subtitle)}</div>'
    ) if subtitle else ""
    badge = f'<span style="margin-right:8px">{badge_html}</span>' if badge_html else ""
    return (
        f'<section id="{sec_id}" class="report-section" style="margin-bottom:20px">'
        f'<div class="sec-hdr" onclick="toggleSection(\'{sec_id}\')" '
        f'    role="button" tabindex="0" '
        f'    onkeydown="if(event.key===\'Enter\'||event.key===\' \')toggleSection(\'{sec_id}\')">'
        f'  <span style="display:flex;align-items:center;justify-content:center;'
        f'    width:36px;height:36px;border-radius:9px;background:{C["bg_accent"]};'
        f'    border:1px solid {C["brand"]}20;flex-shrink:0">'
        f'    {_icon(icon_name, 18, C["brand"])}</span>'
        f'  <div style="flex:1;min-width:0">'
        f'    <div style="font-size:16px;font-weight:700;color:{C["text"]};'
        f'      display:flex;align-items:center;gap:8px;flex-wrap:wrap">'
        f'      {html.escape(title)}{hbtn}</div>'
        f'    {sub_html}'
        f'  </div>'
        f'  {badge}'
        f'  <svg class="sec-chev" width="18" height="18" viewBox="0 0 24 24" fill="none" '
        f'    stroke="{C["text_muted"]}" stroke-width="2.5" stroke-linecap="round">'
        f'    <polyline points="6 9 12 15 18 9"/></svg>'
        f'</div>'
        f'<div class="sec-body" id="{sec_id}-body">'
        f'  {body_html}'
        f'</div>'
        f'</section>'
    )


# ── Main entry point ───────────────────────────────────────────────────────────

def generate_html_report(report: SecurityReport, output_path: str) -> str:
    out = Path(output_path).resolve()
    out.parent.mkdir(parents=True, exist_ok=True)

    overall_score        = _overall_score(report)
    risk_label, risk_fg, risk_bg = _risk_meta(overall_score)
    counts               = report.total_findings()
    date_str             = report.generated_at.strftime("%Y-%m-%d %H:%M UTC")
    source_icon          = "globe" if report.model_source == ModelSource.HUGGINGFACE else "file"
    hf_url               = (
        f"https://huggingface.co/{report.model_id}"
        if report.model_source == ModelSource.HUGGINGFACE else None
    )

    # Generate recommendations
    recs            = _build_recommendations(report, overall_score)
    recs_html       = _recommendations_section(recs)

    # Generate AIBOM data (used both for the section and the embedded JS blob)
    aibom_data      = generate_aibom(report)
    aibom_json_str  = json.dumps(aibom_data, indent=2, default=str)
    # JS-safe: escape </script> inside JSON to prevent XSS
    aibom_js_safe   = aibom_json_str.replace("</", "<\\/")
    safe_model_id   = report.model_id.replace("/", "_").replace("\\", "_")
    aibom_filename  = f"{safe_model_id}_aibom.json"
    aibom_html      = _aibom_section(report, aibom_data)

    module_scores = {
        "Provenance":          _module_score(report.provenance),
        "Adversarial\nRobustness": _module_score(report.adversarial),
        "Privacy":             _module_score(report.privacy),
        "File\nSecurity":      _module_score(report.file_security),
    }

    gauge_svg = _gauge_svg(overall_score, 230)
    radar_svg = _radar_svg(module_scores, 280)
    donut_svg = _donut_svg(counts, 210)

    # Severity pills for header
