# ══════════════════════════════════════════════════════════════════════════════
# Multi-model report
# ══════════════════════════════════════════════════════════════════════════════

def _short_name(model_id: str) -> str:
    """Return the last component of a model ID for compact display."""
    return model_id.split("/")[-1] if "/" in model_id else model_id


def _score_badge(score: float, size: str = "sm") -> str:
    _, fg, bg = _risk_meta(score)
    pad = "3px 10px" if size == "sm" else "5px 14px"
    fs  = "11px"     if size == "sm" else "13px"
    return (
        f'<span style="padding:{pad};border-radius:12px;background:{bg};'
        f'border:1px solid {fg}35;color:{fg};font-size:{fs};font-weight:800">'
        f'{score:.0f}</span>'
    )


def _multi_radar_svg(all_scores: list[dict[str, float]], size: int = 300) -> str:
    """Overlay radar chart for multiple models."""
    labels = ["Provenance", "Adversarial\nRobustness", "Privacy", "File\nSecurity"]
    n = len(labels)
    cx = cy = size / 2
    r  = size * 0.36
    angles = [math.pi / 2 - 2 * math.pi * i / n for i in range(n)]

    PALETTE = [C["brand"], C["high"], C["pass_"], C["medium"], C["critical"]]

    def pt(angle: float, val: float) -> tuple[float, float]:
        ratio = val / 100.0
        return cx + r * ratio * math.cos(angle), cy - r * ratio * math.sin(angle)

    lines = ""
    # Grid rings
    for ring in [25, 50, 75, 100]:
        pts = " ".join(f"{pt(a, ring)[0]:.1f},{pt(a, ring)[1]:.1f}" for a in angles)
        lines += f'<polygon points="{pts}" fill="none" stroke="{C["border"]}" stroke-width="1"/>'
    # Axes
    for a in angles:
        x2, y2 = pt(a, 100)
        lines += f'<line x1="{cx:.1f}" y1="{cy:.1f}" x2="{x2:.1f}" y2="{y2:.1f}" stroke="{C["border"]}" stroke-width="1"/>'

    # Per-model polygons
    for mi, scores in enumerate(all_scores):
        vals = list(scores.values())
        color = PALETTE[mi % len(PALETTE)]
        pts = " ".join(f"{pt(a, v)[0]:.1f},{pt(a, v)[1]:.1f}" for a, v in zip(angles, vals))
        lines += (
            f'<polygon points="{pts}" fill="{color}22" stroke="{color}" '
            f'stroke-width="2" stroke-linejoin="round" opacity="0.85"/>'
        )

    # Axis labels
    for i, (label, angle) in enumerate(zip(labels, angles)):
        lx, ly = pt(angle, 118)
        parts = label.split("\n")
        anchor = "middle" if abs(math.cos(angle)) < 0.3 else ("start" if math.cos(angle) > 0 else "end")
        dy_start = -6 * (len(parts) - 1) / 2
        text_parts = "".join(
            f'<tspan x="{lx:.1f}" dy="{dy_start + j*13:.1f}">{p}</tspan>'
            for j, p in enumerate(parts)
        )
        lines += (
            f'<text x="{lx:.1f}" y="{ly:.1f}" text-anchor="{anchor}" '
            f'font-size="10" fill="{C["text_muted"]}" font-family="inherit">'
            f'{text_parts}</text>'
        )

    return f'<svg viewBox="0 0 {size} {size}" width="{size}" height="{size}" style="display:block;margin:auto">{lines}</svg>'


def _summary_view(reports: list[SecurityReport]) -> str:
    """Summary grid — one card per model."""
    cards = ""
    for idx, rpt in enumerate(reports):
        score   = _overall_score(rpt)
        _, fg, bg = _risk_meta(score)
        counts  = rpt.total_findings()
        src_ico = "globe" if rpt.model_source == ModelSource.HUGGINGFACE else "file"
        hf_url  = (f"https://huggingface.co/{rpt.model_id}"
                   if rpt.model_source == ModelSource.HUGGINGFACE else None)
        name_html = (
            f'<a href="#" onclick="showView(\'model-{idx}\');return false;" '
            f'style="color:{C["brand"]};text-decoration:none;font-weight:700;font-size:15px">'
            f'{html.escape(rpt.model_id)}</a>'
        )
        pills = " ".join(
            f'<span style="padding:2px 8px;border-radius:8px;background:{sbg};'
            f'color:{sfg};font-size:10px;font-weight:700">{counts.get(k,0)} {lbl}</span>'
            for k, lbl, sfg, sbg in [
                ("critical", "Crit", C["critical"], C["critical_bg"]),
                ("high",     "High", C["high"],     C["high_bg"]),
                ("medium",   "Med",  C["medium"],   C["medium_bg"]),
            ] if counts.get(k, 0) > 0
        )
        dim_rows = ""
        for dim_name, result in [
            ("Provenance",  rpt.provenance),
            ("Adversarial", rpt.adversarial),
            ("Privacy",     rpt.privacy),
            ("File Sec.",   rpt.file_security),
        ]:
            ds = _module_score(result)
            _, df, db = _risk_meta(ds)
            dim_rows += (
                f'<div style="display:flex;justify-content:space-between;'
                f'align-items:center;padding:4px 0;border-bottom:1px solid {C["border_light"]}">'
                f'<span style="font-size:11px;color:{C["text_muted"]}">{dim_name}</span>'
                f'<span style="font-size:11px;font-weight:700;color:{df}">{ds:.0f}</span>'
                f'</div>'
            )
        cards += (
            f'<div id="summary-model-{idx}" style="background:{C["bg_card"]};border:1px solid {C["border"]};'
            f'border-radius:12px;padding:20px;display:flex;flex-direction:column;gap:10px;'
            f'box-shadow:0 1px 4px #0000000A">'
            f'<div style="display:flex;align-items:center;gap:10px">'
            f'  <span style="display:flex;align-items:center;justify-content:center;'
            f'    width:40px;height:40px;border-radius:10px;background:{bg};border:1.5px solid {fg}30">'
            f'    {_icon(src_ico, 20, fg)}</span>'
            f'  <div style="min-width:0;flex:1">{name_html}'
            f'    <div style="font-size:10px;color:{C["text_muted"]};margin-top:2px">'
            f'      {html.escape(rpt.model_source.value.upper())}</div></div>'
            f'  {_score_badge(score, "lg")}'
            f'</div>'
            f'<div style="display:flex;gap:4px;flex-wrap:wrap">{pills or "<span style=\'font-size:10px;color:" + C["pass_"] + "\'>No critical/high</span>"}</div>'
            f'<div style="margin-top:4px">{dim_rows}</div>'
            f'<div style="text-align:center;margin-top:4px">'
            f'  <button onclick="showView(\'model-{idx}\')" '
            f'    style="background:{C["brand"]};color:#fff;border:none;padding:7px 20px;'
            f'    border-radius:7px;cursor:pointer;font-size:12px;font-weight:600">View Detail →</button>'
            f'</div>'
            f'</div>'
        )
    return (
        f'<div style="padding:28px 20px">'
        f'<h2 style="font-size:18px;font-weight:800;color:{C["text"]};margin:0 0 18px">Scanned Models</h2>'
        f'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:18px">'
        f'{cards}'
        f'</div>'
        f'</div>'
    )


def _comparison_verdict(reports: list[SecurityReport]) -> str:
    """
    Render a 'Comparison Summary & Recommendation' card.
    Picks the safest model and explains the rationale.
    """
    from modelcheck.models import Severity as _Sev  # already imported at top; alias for clarity

    scores   = [_overall_score(r) for r in reports]
    totals   = [r.total_findings() for r in reports]
    postures = [_compliance_posture(r) for r in reports]

    n_violations = [len(p) for p in postures]   # number of distinct frameworks violated

    dim_scores = [
        {
            "Provenance":  _module_score(r.provenance),
            "Adversarial": _module_score(r.adversarial),
            "Privacy":     _module_score(r.privacy),
            "File Sec.":   _module_score(r.file_security),
        }
        for r in reports
    ]

    # ── Rank: primary = fewest critical; secondary = fewest high;
    #          tertiary = highest overall score; quaternary = fewest violations
    def _rank_key(i: int):
        return (
            totals[i].get("critical", 0),
            totals[i].get("high", 0),
            -scores[i],
            n_violations[i],
        )

    ranked = sorted(range(len(reports)), key=_rank_key)
    winner_idx = ranked[0]
    winner     = reports[winner_idx]
    w_score    = scores[winner_idx]
    w_totals   = totals[winner_idx]
    w_dims     = dim_scores[winner_idx]
    w_posture  = postures[winner_idx]
    w_name     = _short_name(winner.model_id)

    _, w_fg, w_bg = _risk_meta(w_score)

    # ── Build "Why this model?" bullets ──────────────────────────────────────
    why_bullets: list[str] = []

    # Score comparison
    if len(reports) > 1:
        others_scores = [f"{scores[j]:.0f}" for j in ranked[1:]]
        why_bullets.append(
            f"Highest overall security score: <b>{w_score:.0f}/100</b>"
            + (f" (vs {', '.join(others_scores)})" if others_scores else "")
        )
    else:
        why_bullets.append(f"Overall security score: <b>{w_score:.0f}/100</b>")

    # Critical / high finding counts
    crits = w_totals.get("critical", 0)
    highs = w_totals.get("high", 0)
    if crits == 0 and highs == 0:
        why_bullets.append("No critical or high-severity findings")
    elif crits == 0:
        why_bullets.append(f"No critical findings; {highs} high-severity finding{'s' if highs != 1 else ''}")
    else:
        why_bullets.append(f"{crits} critical and {highs} high-severity finding{'s' if highs+crits != 1 else ''}")

    # Best dimension(s)
    best_dim  = max(w_dims, key=lambda k: w_dims[k])
    best_val  = w_dims[best_dim]
    if best_val >= 70:
        # Check if winner leads in this dimension across all models
        all_vals  = [dim_scores[j][best_dim] for j in range(len(reports))]
        if best_val == max(all_vals):
            why_bullets.append(
                f"Strongest in <b>{best_dim}</b> ({best_val:.0f}/100)"
                + (f" — best across all models" if len(reports) > 1 else "")
            )

    # Compliance
    n_viol = len(w_posture)
    if n_viol == 0:
        why_bullets.append("No compliance framework violations detected")
    else:
        why_bullets.append(
            f"{n_viol} of {len(_ALL_FRAMEWORKS)} compliance framework{'s' if n_viol != 1 else ''} violated"
        )

    # ── Build "Remaining concerns" bullets ──────────────────────────────────
    concerns: list[str] = []
    if crits > 0:
        concerns.append(
            f"<b>{crits} critical finding{'s' if crits != 1 else ''}</b> must be remediated before deployment"
        )
    if highs > 0 and crits == 0:
        concerns.append(
            f"{highs} high-severity finding{'s' if highs != 1 else ''} should be addressed before production use"
        )
    weak_dims = [d for d, v in w_dims.items() if v < 60]
    for d in weak_dims:
        concerns.append(f"{d} score ({w_dims[d]:.0f}/100) is below the recommended threshold of 60")

    # ── "Notes on other models" ───────────────────────────────────────────────
    notes: list[str] = []
    for j in ranked[1:]:
        other      = reports[j]
        o_name     = _short_name(other.model_id)
        o_crits    = totals[j].get("critical", 0)
        o_highs    = totals[j].get("high", 0)
        o_score    = scores[j]
        _, o_fg, _ = _risk_meta(o_score)
        parts = [f"score <b>{o_score:.0f}/100</b>"]
        if o_crits:
            crit_clr = C["critical"]
            parts.append(f"<b style='color:{crit_clr}'>{o_crits} critical</b>")
        if o_highs:
            parts.append(f"{o_highs} high")
        viol_j = len(postures[j])
        if viol_j > n_violations[winner_idx]:
            parts.append(f"{viol_j} framework violations")
        notes.append(
            f"<b>{html.escape(o_name)}</b>: {'; '.join(parts)}"
        )

    # ── Render ────────────────────────────────────────────────────────────────
    def _li(text: str, color: str = C["text_muted"], icon: str = "•") -> str:
        return (
            f'<li style="margin-bottom:6px;color:{color};font-size:13px;line-height:1.5">'
            f'<span style="font-weight:600;margin-right:4px">{icon}</span>{text}</li>'
        )

    why_html = "".join(_li(b, C["text"]) for b in why_bullets)
    concerns_html = "".join(_li(b, C["high"]) for b in concerns) if concerns else ""
    notes_html    = "".join(_li(n, C["text_muted"]) for n in notes) if notes else ""

    concerns_block = ""
    if concerns_html:
        concerns_block = (
            f'<div style="margin-top:16px">'
            f'<div style="font-size:11px;font-weight:700;color:{C["high"]};'
            f'text-transform:uppercase;letter-spacing:.05em;margin-bottom:6px">'
            f'Remaining Concerns</div>'
            f'<ul style="margin:0;padding-left:0;list-style:none">{concerns_html}</ul>'
            f'</div>'
        )

    notes_block = ""
    if notes_html:
        notes_block = (
            f'<div style="margin-top:16px">'
            f'<div style="font-size:11px;font-weight:700;color:{C["text_muted"]};'
            f'text-transform:uppercase;letter-spacing:.05em;margin-bottom:6px">'
            f'Other Models</div>'
            f'<ul style="margin:0;padding-left:0;list-style:none">{notes_html}</ul>'
            f'</div>'
        )

    # Winner badge pill
    badge_label = "Recommended" if crits == 0 else "Relatively Safer"
    badge_color = C["pass_"] if crits == 0 else C["medium"]
    badge_bg    = C["pass_bg"] if crits == 0 else C["medium_bg"]

    # Caveat if even winner has critical issues
    top_caveat = ""
    if crits > 0:
        top_caveat = (
            f'<div style="margin-bottom:12px;padding:8px 12px;border-radius:6px;'
            f'background:{C["critical_bg"]};border-left:3px solid {C["critical"]};'
            f'font-size:12px;color:{C["critical"]};font-weight:600">'
            f'⚠ Even the top-ranked model has critical findings. '
            f'No model in this set is currently safe for unrestricted deployment.'
            f'</div>'
        )

    return (
        f'<div style="margin-top:28px;background:{C["bg_card"]};border:1px solid {C["border"]};'
        f'border-radius:12px;overflow:hidden">'
        # Section header
        f'<div style="padding:14px 20px;background:{C["bg_raised"]};'
        f'border-bottom:1px solid {C["border"]};display:flex;align-items:center;gap:10px">'
        f'{_icon("shield", 18, C["brand"])}'
        f'<span style="font-size:15px;font-weight:800;color:{C["text"]}">Comparison Summary &amp; Recommendation</span>'
        f'</div>'
        # Body
        f'<div style="padding:20px 24px">'
        f'{top_caveat}'
        # Winner card
        f'<div style="display:flex;align-items:flex-start;gap:16px;'
        f'padding:16px;border-radius:10px;background:{w_bg}33;'
        f'border:1px solid {w_fg}44;margin-bottom:16px">'
        f'<div style="flex:0 0 auto;font-size:28px;line-height:1">🏆</div>'
        f'<div style="flex:1;min-width:0">'
        f'<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:4px">'
        f'<span style="font-size:15px;font-weight:800;color:{C["text"]}">{html.escape(winner.model_id)}</span>'
        f'<span style="padding:2px 8px;border-radius:20px;font-size:10px;font-weight:800;'
        f'background:{badge_bg};color:{badge_color}">{badge_label}</span>'
        f'</div>'
        f'<div style="display:flex;gap:12px;flex-wrap:wrap;align-items:center">'
        f'{_score_badge(w_score, 32)}'
        f'<span style="font-size:12px;color:{C["text_muted"]}">'
        f'{w_totals.get("critical", 0)} critical · '
        f'{w_totals.get("high", 0)} high · '
        f'{w_totals.get("medium", 0)} medium findings'
        f'</span>'
        f'</div>'
        f'</div>'
        f'</div>'
        # Why
        f'<div style="margin-bottom:4px">'
        f'<div style="font-size:11px;font-weight:700;color:{C["brand"]};'
        f'text-transform:uppercase;letter-spacing:.05em;margin-bottom:6px">'
        f'Why this model?</div>'
        f'<ul style="margin:0;padding-left:0;list-style:none">{why_html}</ul>'
        f'</div>'
        f'{concerns_block}'
        f'{notes_block}'
        f'</div>'  # /body
        f'</div>'  # /card
    )


def _compare_view(reports: list[SecurityReport]) -> str:
    """Side-by-side comparison table + multi-model radar."""
    scores     = [_overall_score(r) for r in reports]
    all_mod    = [
        {
            "Provenance":  _module_score(r.provenance),
            "Adversarial": _module_score(r.adversarial),
            "Privacy":     _module_score(r.privacy),
            "File Sec.":   _module_score(r.file_security),
        }
        for r in reports
    ]

    PALETTE = ["#1578F7", "#BC4C00", "#14A24A", "#7D4E00", "#CF222E"]

    # Header row
    th = "".join(
        f'<th style="padding:10px 14px;text-align:center;font-size:12px;'
        f'font-weight:700;color:{PALETTE[i % len(PALETTE)]};'
        f'border-bottom:2px solid {PALETTE[i % len(PALETTE)]}44;white-space:nowrap">'
        f'<button onclick="showView(\'model-{i}\')" '
        f'style="background:none;border:none;cursor:pointer;font-weight:700;'
        f'color:{PALETTE[i % len(PALETTE)]};font-size:12px">'
        f'{html.escape(_short_name(r.model_id))}</button></th>'
        for i, r in enumerate(reports)
    )

    def _dim_row(label: str, vals: list[float]) -> str:
        cells = ""
        best  = max(vals)
        for i, v in enumerate(vals):
            _, fg, bg = _risk_meta(v)
            is_best = (v == best and len(reports) > 1)
            cells += (
                f'<td style="padding:9px 14px;text-align:center;'
                f'background:{"" if not is_best else bg}">'
                f'<span style="font-size:13px;font-weight:700;color:{fg}">{v:.0f}</span>'
                f'{"<br/><span style=\'font-size:9px;color:" + C["pass_"] + "\'>▲ best</span>" if is_best else ""}'
                f'</td>'
            )
        return (
            f'<tr style="border-bottom:1px solid {C["border_light"]}">'
            f'<td style="padding:9px 14px;font-size:12px;font-weight:600;'
            f'color:{C["text_muted"]};white-space:nowrap">{html.escape(label)}</td>'
            f'{cells}</tr>'
        )

    def _count_row(label: str, sev_key: str, fg: str, bg: str) -> str:
        vals = [r.total_findings().get(sev_key, 0) for r in reports]
        best_val = min(vals)
        cells = ""
        for i, v in enumerate(vals):
            is_best = (v == best_val and len(reports) > 1)
            cells += (
                f'<td style="padding:9px 14px;text-align:center;'
                f'background:{"" if not is_best or v > 0 else C["pass_bg"]}">'
                f'<span style="font-size:13px;font-weight:700;color:{fg if v > 0 else C["pass_"]}">'
                f'{v}</span>'
                f'{"<br/><span style=\'font-size:9px;color:" + C["pass_"] + "\'>▲ best</span>" if is_best else ""}'
                f'</td>'
            )
        return (
            f'<tr style="border-bottom:1px solid {C["border_light"]}">'
            f'<td style="padding:9px 14px;font-size:12px;font-weight:600;'
            f'color:{C["text_muted"]};white-space:nowrap">'
            f'<span style="padding:2px 7px;border-radius:6px;background:{bg};color:{fg};'
            f'font-size:10px;font-weight:700">{html.escape(label)}</span></td>'
            f'{cells}</tr>'
        )

    # Overall score row
    overall_cells = ""
    best_score = max(scores)
    for i, (s, r) in enumerate(zip(scores, reports)):
        _, fg, bg = _risk_meta(s)
        is_best = (s == best_score and len(reports) > 1)
        overall_cells += (
            f'<td style="padding:9px 14px;text-align:center;background:{bg if is_best else ""}">'
            f'<span style="font-size:15px;font-weight:800;color:{fg}">{s:.0f}</span>'
            f'{"<br/><span style=\'font-size:9px;color:" + C["pass_"] + "\'>▲ best</span>" if is_best else ""}'
            f'</td>'
        )

    table = (
        f'<table style="width:100%;border-collapse:collapse;background:{C["bg_card"]};'
        f'border:1px solid {C["border"]};border-radius:10px;overflow:hidden">'
        f'<thead><tr style="background:{C["bg_raised"]}">'
        f'<th style="padding:10px 14px;text-align:left;font-size:12px;color:{C["text_muted"]};'
        f'font-weight:600">Dimension</th>{th}</tr></thead>'
        f'<tbody>'
        f'<tr style="border-bottom:2px solid {C["border"]};background:{C["bg_accent"]}">'
        f'<td style="padding:9px 14px;font-size:12px;font-weight:700;color:{C["text"]}">Overall Score</td>'
        f'{overall_cells}</tr>'
        + _dim_row("Provenance",    [m["Provenance"]  for m in all_mod])
        + _dim_row("Adversarial",   [m["Adversarial"] for m in all_mod])
        + _dim_row("Privacy",       [m["Privacy"]     for m in all_mod])
        + _dim_row("File Security", [m["File Sec."]   for m in all_mod])
        + _count_row("Critical", "critical", C["critical"], C["critical_bg"])
        + _count_row("High",     "high",     C["high"],     C["high_bg"])
        + _count_row("Medium",   "medium",   C["medium"],   C["medium_bg"])
        + _count_row("Low",      "low",      C["low"],      C["low_bg"])
        + _count_row("Total",    "total",    C["text"],     C["bg_raised"])
        + f'</tbody></table>'
    )

    # Legend for radar
    legend = "".join(
        f'<span style="display:inline-flex;align-items:center;gap:5px;font-size:11px;color:{C["text_muted"]}">'
        f'<span style="width:12px;height:12px;border-radius:3px;background:{PALETTE[i % len(PALETTE)]};'
        f'display:inline-block"></span>{html.escape(_short_name(r.model_id))}</span>'
        for i, r in enumerate(reports)
    )

    radar = _multi_radar_svg(all_mod, 300)

    # ── Compliance comparison ─────────────────────────────────────────────────
    fw_colors = _load_frameworks()["colors"]
    postures  = [_compliance_posture(r) for r in reports]

    SEV_ORDER = {Severity.CRITICAL: 0, Severity.HIGH: 1, Severity.MEDIUM: 2,
                 Severity.LOW: 3, Severity.INFO: 4, Severity.UNKNOWN: 5}

    fw_th = "".join(
        f'<th style="padding:8px 12px;text-align:center;font-size:11px;font-weight:700;'
        f'color:{PALETTE[i % len(PALETTE)]};border-bottom:2px solid {PALETTE[i % len(PALETTE)]}44">'
        f'{html.escape(_short_name(r.model_id))}</th>'
        for i, r in enumerate(reports)
    )

    fw_rows = ""
    for fname in _ALL_FRAMEWORKS:
        col    = fw_colors.get(fname, {})
        hdr_bg = col.get("fg", C["text_muted"])
        cells  = ""
        for posture in postures:
            items = posture.get(fname, [])
            if not items:
                cells += (
                    f'<td style="padding:8px 12px;text-align:center;background:{C["pass_bg"]}">'
                    f'<span style="font-size:10px;color:{C["pass_"]};font-weight:700">✓ Clear</span></td>'
                )
            else:
                worst = min(items, key=lambda x: SEV_ORDER.get(x["severity"], 5))
                ws_fg, ws_bg = SEV_COLOR[worst["severity"]]
                chips = " ".join(
                    (lambda rid=it["ref_id"], rurl=it["url"], rname=it["name"],
                                  sfg=SEV_COLOR[it["severity"]][0], sbg=SEV_COLOR[it["severity"]][1]:
                        f'<a href="{html.escape(rurl)}" target="_blank" rel="noopener" '
                        f'title="{html.escape(rname)}" '
                        f'style="display:inline-block;padding:1px 5px;border-radius:3px;'
                        f'background:{sbg};color:{sfg};'
                        f'font-size:9px;font-weight:700;text-decoration:none;'
                        f'border:1px solid {sfg}30">'
                        f'{html.escape(rid)}</a>'
                    )()
                    for it in items
                )
                cells += (
                    f'<td style="padding:8px 12px;text-align:center;background:{ws_bg}22">'
                    f'<div style="display:flex;flex-wrap:wrap;gap:3px;justify-content:center">{chips}</div></td>'
                )
        fw_rows += (
            f'<tr style="border-bottom:1px solid {C["border_light"]}">'
            f'<td style="padding:8px 12px;white-space:nowrap">'
            f'  <span style="display:inline-block;padding:2px 8px;border-radius:4px;'
            f'  background:{hdr_bg};color:#FFFFFF;font-size:10px;font-weight:800">'
            f'  {html.escape(fname)}</span></td>'
            f'{cells}</tr>'
        )

    fw_table = (
        f'<table style="width:100%;border-collapse:collapse;background:{C["bg_card"]};'
        f'border:1px solid {C["border"]};border-radius:10px;overflow:hidden">'
        f'<thead><tr style="background:{C["bg_raised"]}">'
        f'<th style="padding:8px 12px;text-align:left;font-size:11px;color:{C["text_muted"]};font-weight:600">Framework</th>'
        f'{fw_th}</tr></thead>'
        f'<tbody>{fw_rows}</tbody></table>'
    )

    return (
        f'<div style="padding:28px 20px">'
        f'<h2 style="font-size:18px;font-weight:800;color:{C["text"]};margin:0 0 18px">Model Comparison</h2>'
        f'<div style="display:grid;grid-template-columns:1fr auto;gap:28px;align-items:start">'
        f'<div>{table}</div>'
        f'<div style="background:{C["bg_card"]};border:1px solid {C["border"]};border-radius:10px;padding:20px">'
        f'<div style="font-size:12px;font-weight:600;color:{C["text_muted"]};margin-bottom:10px">Dimension Radar</div>'
        f'{radar}'
        f'<div style="display:flex;gap:12px;flex-wrap:wrap;margin-top:10px;justify-content:center">{legend}</div>'
        f'</div>'
        f'</div>'
        f'<h2 style="font-size:16px;font-weight:800;color:{C["text"]};margin:28px 0 14px">'
        f'{_icon("layers",16,C["brand"])} Compliance Framework Comparison</h2>'
        f'{fw_table}'
        f'{_comparison_verdict(reports)}'
        f'</div>'
    )


def _model_detail_view(report: SecurityReport, idx: int) -> str:
    """Per-model detail view — full report content with prefixed section IDs."""
    pfx             = f"model-{idx}"
    overall_score   = _overall_score(report)
    risk_label, risk_fg, risk_bg = _risk_meta(overall_score)
    counts          = report.total_findings()
    date_str        = report.generated_at.strftime("%Y-%m-%d %H:%M UTC")
    hf_url          = (f"https://huggingface.co/{report.model_id}"
                       if report.model_source == ModelSource.HUGGINGFACE else None)
    source_icon     = "globe" if report.model_source == ModelSource.HUGGINGFACE else "file"

    recs        = _build_recommendations(report, overall_score)
    recs_html   = _recommendations_section(recs)

    aibom_data      = generate_aibom(report)
    aibom_html      = _aibom_section(report, aibom_data, model_idx=idx)

    module_scores = {
        "Provenance":          _module_score(report.provenance),
        "Adversarial\nRobustness": _module_score(report.adversarial),
        "Privacy":             _module_score(report.privacy),
        "File\nSecurity":      _module_score(report.file_security),
    }

    gauge_svg   = _gauge_svg(overall_score, 200)
    radar_svg   = _radar_svg(module_scores, 240)
    donut_svg   = _donut_svg(counts, 190)

    pills = "".join(
        f'<span style="padding:3px 11px;border-radius:12px;background:{bg};'
        f'border:1px solid {fg}35;color:{fg};font-size:12px;font-weight:700">'
        f'{counts.get(key,0)} {label}</span>'
        for key, label, fg, bg in [
            ("critical","Critical", C["critical"], C["critical_bg"]),
            ("high",    "High",     C["high"],     C["high_bg"]),
            ("medium",  "Medium",   C["medium"],   C["medium_bg"]),
            ("low",     "Low",      C["low"],      C["low_bg"]),
        ] if counts.get(key, 0) > 0
    )

    modules_html = "".join(
        _module_section(r, ico, hk)
        for r, ico, hk in [
            (report.provenance,    "globe",  "provenance"),
            (report.adversarial,   "sword",  "adversarial"),
            (report.privacy,       "lock",   "privacy"),
            (report.file_security, "file",   "file_security"),
        ] if r
    )

    def cs(sec_id, *args, **kwargs):
        return _collapsible_section(f"{pfx}-{sec_id}", *args, **kwargs)

    return f'''
<div id="view-{pfx}" class="view with-nav" style="display:none">
  <!-- Per-model mini header -->
  <div style="background:linear-gradient(135deg,#050525 0%,#0d1a6b 50%,{C["bg_accent"]} 100%);
    padding:20px 20px 16px;border-bottom:1px solid {C["border"]}">
    <div style="max-width:1180px;margin:0 auto;display:flex;align-items:center;gap:14px;flex-wrap:wrap">
      <span style="display:flex;align-items:center;justify-content:center;
        width:44px;height:44px;border-radius:12px;background:{risk_bg};border:1.5px solid {risk_fg}30">
        {_icon(source_icon, 22, risk_fg)}</span>
      <div style="flex:1;min-width:0">
        {'<a href="' + html.escape(hf_url) + '" target="_blank" rel="noopener" style="text-decoration:none">' if hf_url else ''}
        <div style="font-size:18px;font-weight:800;color:#FFFFFF;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">
          {html.escape(report.model_id)}{_icon("link",14,"#FFFFFF80") if hf_url else ""}</div>
        {'</a>' if hf_url else ''}
        <div style="font-size:11px;color:#FFFFFFAA;margin-top:3px">{html.escape(date_str)}</div>
      </div>
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;flex-shrink:0">
        {pills}
        <span style="padding:5px 14px;border-radius:20px;background:{risk_bg};
          border:1px solid {risk_fg}35;color:{risk_fg};font-size:12px;font-weight:800">
          {html.escape(risk_label)}</span>
      </div>
    </div>
  </div>

  <div class="container" style="margin-top:24px;padding-bottom:40px">
    {cs("sec-dashboard", "activity",
        "Security Dashboard", "Overall security posture across all four dimensions",
        "",
        (
            '<div style="padding:16px 0 8px"><div class="grid-3">'
            '<div class="chart-card"><div class="chart-title">' + _icon("zap",14,C["brand"]) + ' Overall Score</div>' + gauge_svg + '</div>'
            '<div class="chart-card"><div class="chart-title">' + _icon("eye",14,C["brand"]) + ' Dimension Radar</div>' + radar_svg + '</div>'
            '<div class="chart-card"><div class="chart-title">' + _icon("alert",14,C["brand"]) + ' Finding Distribution</div>' + donut_svg + '</div>'
            '</div></div>'
        ),
    )}

    {cs("sec-provenance", "globe",
        "Supply Chain & Provenance", "Model origin, authorship, and licensing",
        "provenance",
        _provenance_grid(report),
        _status_badge(report.provenance.status) if report.provenance else "",
    )}

    {cs("sec-module-scores", "cpu",
        "Module Scores", "Per-dimension security score (100 = no findings)",
        "module_scores",
        '<div style="padding:16px 0 4px">' + _module_score_cards(report) + '</div>',
    )}

    {cs("sec-compliance", "layers",
        "Compliance & Framework Coverage",
        str(sum(1 for f in _ALL_FRAMEWORKS if f in _compliance_posture(report))) + " of " + str(len(_ALL_FRAMEWORKS)) + " frameworks violated",
        "",
        '<div style="padding:16px">' + _compliance_section(report) + '</div>',
    )}

    {cs("sec-findings", "shield",
        "Detailed Findings", str(counts["total"]) + " total \u2014 click any row to expand",
        "findings",
        (
            '<div style="padding:16px">'
            '<div style="display:flex;gap:8px;margin-bottom:14px;justify-content:flex-end">'
            "<button onclick=\"document.querySelectorAll('#view-" + pfx + " details').forEach(d=>d.open=true)\""
            ' style="background:' + C["bg_card"] + ';border:1px solid ' + C["border"] + ';color:' + C["text_muted"] + ';'
            'padding:5px 14px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">Expand all</button>'
            "<button onclick=\"document.querySelectorAll('#view-" + pfx + " details').forEach(d=>d.open=false)\""
            ' style="background:' + C["bg_card"] + ';border:1px solid ' + C["border"] + ';color:' + C["text_muted"] + ';'
            'padding:5px 14px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">Collapse all</button>'
            '</div>' + modules_html + '</div>'
        ),
    )}

    {cs("sec-aibom", "list",
        "AI Bill of Materials", "CycloneDX 1.5 machine-readable AI BOM",
        "aibom",
        '<div style="padding:16px">' + aibom_html + '</div>',
    )}

    {cs("sec-recommendations", "zap",
        "Security Recommendations", str(len(recs)) + " prioritised action(s) based on findings",
        "recommendations",
        '<div style="padding:16px">' + recs_html + '</div>',
    )}
  </div>
</div>'''


def _topbar_html(reports: list[SecurityReport]) -> str:
    """Sticky top bar: AccuKnox brand on left, tabs on right."""
    PALETTE = ["#1578F7", "#BC4C00", "#14A24A", "#7D4E00", "#CF222E"]

    brand = (
        f'<a href="https://accuknox.com" target="_blank" rel="noopener"'
        f' style="display:flex;align-items:center;gap:8px;text-decoration:none;flex-shrink:0;padding:0 4px">'
        f'  {_icon_img(26)}'
        f'  <span style="font-size:15px;font-weight:800;color:#FFFFFF;letter-spacing:-0.3px">AccuKnox</span>'
        f'</a>'
        f'<div style="width:1px;height:22px;background:#FFFFFF30;flex-shrink:0;margin:0 6px"></div>'
        f'<span style="font-size:11px;font-weight:600;color:#FFFFFFAA;'
        f'  padding:2px 8px;border-radius:4px;background:#FFFFFF12;border:1px solid #FFFFFF20;flex-shrink:0">'
        f'  modelcheck</span>'
        f'<div style="width:1px;height:22px;background:#FFFFFF30;flex-shrink:0;margin:0 6px"></div>'
    )

    tabs = (
        '<button class="topbar-tab active" data-view="summary" onclick="showView(\'summary\')">'
        f'{_icon("activity", 14, "currentColor")} Summary</button>'
        '<button class="topbar-tab" data-view="compare" onclick="showView(\'compare\')">'
        f'{_icon("trending", 14, "currentColor")} Compare</button>'
    )
    for i, rpt in enumerate(reports):
        _, fg, _ = _risk_meta(_overall_score(rpt))
        tabs += (
            f'<button class="topbar-tab" data-view="model-{i}" onclick="showView(\'model-{i}\')">'
            f'<span style="display:inline-block;width:8px;height:8px;border-radius:50%;'
            f'background:{fg};margin-right:4px;flex-shrink:0"></span>'
            f'{html.escape(_short_name(rpt.model_id))}</button>'
        )

    return f'<div id="topbar">{brand}{tabs}</div>'


def _multi_navbar_html(reports: list[SecurityReport]) -> str:
    """Left sidebar for multi-report: context switches with active view."""
    PALETTE = ["#1578F7", "#BC4C00", "#14A24A", "#7D4E00", "#CF222E"]
    toggle_btn = (
        '<button id="nav-toggle" onclick="toggleSidebar()" '
        'aria-label="Toggle navigation" title="Collapse / expand sidebar">'
        '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" '
        'stroke="currentColor" stroke-width="2.5" stroke-linecap="round">'
        '<line x1="3" y1="12" x2="21" y2="12"/>'
        '<line x1="3" y1="6"  x2="21" y2="6"/>'
        '<line x1="3" y1="18" x2="21" y2="18"/>'
        '</svg></button>'
    )

    def nav_item(href: str, icon: str, label: str, dot_color: str = "", onclick: str = "") -> str:
        oc = f' onclick="{onclick}"' if onclick else ""
        dot = (
            f'<span style="width:7px;height:7px;border-radius:50%;'
            f'background:{dot_color};flex-shrink:0"></span>'
            if dot_color else ""
        )
        return (
            f'<li><a class="nav-item" href="{href}"{oc}>'
            f'<span class="nav-icon">{_icon(icon, 16, "currentColor")}</span>'
            f'<span class="nav-label">{html.escape(label)}</span>'
            f'{dot}</a></li>'
        )

    # ── Summary nav context ──
    sum_items = "".join(
        nav_item(
            f"#summary-model-{i}",
            "globe" if r.model_source == ModelSource.HUGGINGFACE else "file",
            _short_name(r.model_id),
            PALETTE[i % len(PALETTE)],
        )
        for i, r in enumerate(reports)
    )

    # ── Per-model nav contexts ──
    model_navs = ""
    for i, rpt in enumerate(reports):
        score  = _overall_score(rpt)
        _, fg, _ = _risk_meta(score)
        counts = rpt.total_findings()
        pfx    = f"model-{i}"
        sec_items = (
            nav_item(f"#{pfx}-sec-dashboard",    "activity", "Dashboard",       "",
                     f"expandSection('{pfx}-sec-dashboard')")
            + nav_item(f"#{pfx}-sec-provenance",    "globe",    "Provenance",      fg,
                     f"expandSection('{pfx}-sec-provenance')")
            + nav_item(f"#{pfx}-sec-module-scores","cpu",      "Module Scores",   "",
                     f"expandSection('{pfx}-sec-module-scores')")
            + nav_item(f"#{pfx}-sec-compliance",   "layers",   "Compliance",      C["brand"],
                     f"expandSection('{pfx}-sec-compliance')")
            + nav_item(f"#{pfx}-sec-findings",     "shield",   f"Findings ({counts['total']})",
                     C["critical"] if counts.get("critical",0) else C["high"] if counts.get("high",0) else "",
                     f"expandSection('{pfx}-sec-findings')")
            + nav_item(f"#{pfx}-sec-aibom",        "list",     "AIBOM",           C["brand"],
                     f"expandSection('{pfx}-sec-aibom')")
            + nav_item(f"#{pfx}-sec-recommendations","zap",    "Recommendations", "",
                     f"expandSection('{pfx}-sec-recommendations')")
        )
        model_navs += (
            f'<ul id="nav-ctx-model-{i}" class="nav-list nav-ctx" style="display:none">'
            f'{sec_items}</ul>'
        )

    return (
        f'<nav id="sidebar" aria-label="Report navigation">'
        f'<div class="nav-brand">'
        f'  <span class="nav-icon nav-brand-icon">{_icon("shield", 18, C["brand"])}</span>'
        f'  <span class="nav-label" style="font-weight:800;font-size:13px;color:#FFFFFF">modelcheck</span>'
        f'  {toggle_btn}'
        f'</div>'
        f'<ul id="nav-ctx-summary" class="nav-list nav-ctx">{sum_items}</ul>'
        f'{model_navs}'
        f'<div class="nav-footer">'
        f'  <span class="nav-label" style="font-size:10px;color:#FFFFFF55">modelcheck</span>'
        f'</div>'
        f'</nav>'
    )


def _multi_css_extra() -> str:
    """Additional CSS for top bar and multi-view layout."""
    return f"""
/* ── Top bar ──────────────────────────────────────────────────────────────── */
:root {{ --topbar-h: 48px; }}
#topbar {{
  position:fixed;top:0;left:0;right:0;height:var(--topbar-h);
  background:#050525;border-bottom:1px solid #1a1a4a;
  box-shadow:0 2px 12px #00000040;
  display:flex;align-items:center;padding:0 14px;gap:0;
  z-index:300;overflow-x:auto;
}}
#topbar::-webkit-scrollbar {{ height:3px }}
#topbar::-webkit-scrollbar-thumb {{ background:#FFFFFF30;border-radius:2px }}
.topbar-tab {{
  background:none;border:none;color:#FFFFFFAA;cursor:pointer;
  padding:0 14px;height:44px;font-size:12px;font-weight:600;
  display:inline-flex;align-items:center;gap:6px;white-space:nowrap;
  border-bottom:2px solid transparent;transition:color .15s,border-color .15s;
  flex-shrink:0;
}}
.topbar-tab:hover {{ color:#FFFFFF }}
.topbar-tab.active {{ color:#FFFFFF;border-bottom-color:{C["brand"]} }}
/* ── Sidebar positioned below topbar ──────────────────────────────────────── */
#sidebar {{ top:var(--topbar-h)!important }}
/* ── Main offset accounts for topbar ──────────────────────────────────────── */
.with-nav {{ margin-top:var(--topbar-h)!important }}
/* ── View containers ──────────────────────────────────────────────────────── */
.view {{ min-height:calc(100vh - var(--topbar-h)) }}
"""


def generate_multi_html_report(reports: list[SecurityReport], output_path: str) -> str:
    """Generate a single self-contained HTML report for multiple scanned models."""
    out = Path(output_path).resolve()
    out.parent.mkdir(parents=True, exist_ok=True)

    tool_version = reports[0].tool_version if reports else "0.1.0"
    date_str     = reports[0].generated_at.strftime("%Y-%m-%d %H:%M UTC") if reports else ""

    topbar   = _topbar_html(reports)
    sidebar  = _multi_navbar_html(reports)
    sum_view = _summary_view(reports)
    cmp_view = _compare_view(reports)

    # Per-model detail views + AIBOM JS blobs
    model_views   = ""
    aibom_js_vars = ""
    for idx, rpt in enumerate(reports):
        model_views += _model_detail_view(rpt, idx)
        aibom_data   = generate_aibom(rpt)
        aibom_json   = json.dumps(aibom_data, indent=2, default=str).replace("</", "<\\/")
        safe_id      = rpt.model_id.replace("/", "_").replace("\\", "_")
        aibom_js_vars += f'AIBOMS[{idx}] = {aibom_json};\nAIBOM_NAMES[{idx}] = {json.dumps(safe_id + "_aibom.json")};\n'

    model_count = len(reports)

    doc = f'''<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <title>modelcheck — {model_count} Model Security Report</title>
  <style>{_css()}{_multi_css_extra()}</style>
</head>
<body>
{topbar}
{sidebar}

<!-- ═══ VIEWS ════════════════════════════════════════════════════════════════ -->

<!-- Summary view -->
<div id="view-summary" class="view with-nav">
{sum_view}
</div>

<!-- Compare view -->
<div id="view-compare" class="view with-nav" style="display:none">
{cmp_view}
</div>

<!-- Per-model detail views -->
{model_views}

<!-- ═══ FOOTER ══════════════════════════════════════════════════════════════ -->
<footer id="footer" class="with-nav" style="background:{C["bg_card"]};border-top:1px solid {C["border"]};
  padding:16px 20px;margin-top:20px">
  <div style="max-width:1180px;margin:0 auto;
    display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px">
    <a href="https://accuknox.com" target="_blank" rel="noopener"
       style="display:flex;align-items:center;gap:10px;text-decoration:none">
      {_logo_img(24)}
      <div style="font-size:10px;color:{C["text_muted"]}">Cloud Native Security Platform</div>
    </a>
    <div style="font-size:11px;color:{C["text_light"]};text-align:right">
      modelcheck v{html.escape(tool_version)} &middot; {html.escape(date_str)} &middot; {model_count} models<br/>
      For authorised security testing only.<br/>
      <a href="https://huggingface.co/settings/tokens/new?tokenType=fineGrained" target="_blank" rel="noopener"
         title="Create a fine-grained token with: Read access to contents of all public gated repos you can access"
         style="color:{C["brand"]};text-decoration:none;font-size:10px">
        {_icon("key", 10, C["brand"])} Create HF_TOKEN (fine-grained)
      </a>
    </div>
  </div>
</footer>

<!-- Help popover -->
<div id="help-popover" role="tooltip" aria-live="polite">
  <div id="help-popover-title">
    <span id="help-popover-title-text"></span>
    <button id="help-popover-close" aria-label="Close">&#x2715;</button>
  </div>
  <div id="help-popover-body"></div>
</div>

<script>
const HELP = {{}};
{_help_js_data()}

const pop    = document.getElementById("help-popover");
const ptitle = document.getElementById("help-popover-title-text");
const pbody  = document.getElementById("help-popover-body");
let   activeBtn = null;
function showHelp(btn) {{
  const key = btn.dataset.help, data = HELP[key];
  if (!data) return;
  ptitle.textContent = data[0]; pbody.innerHTML = data[1];
  pop.classList.add("visible"); activeBtn = btn; positionPop(btn);
}}
function positionPop(btn) {{
  const br=btn.getBoundingClientRect(),pw=pop.offsetWidth||340,ph=pop.offsetHeight||160,vw=window.innerWidth,vh=window.innerHeight;
  let left=br.right+10,top=br.top;
  if(left+pw>vw-10)left=Math.max(10,br.left-pw-10);
  if(top+ph>vh-10)top=Math.max(10,vh-ph-10);
  pop.style.left=left+"px"; pop.style.top=top+"px";
}}
function closeHelp(){{ pop.classList.remove("visible"); activeBtn=null; }}
function helpBtnClick(e,btn){{ e.stopPropagation(); if(activeBtn===btn){{closeHelp();return;}} showHelp(btn); }}
document.getElementById("help-popover-close").addEventListener("click",closeHelp);
document.addEventListener("click",e=>{{ if(!pop.contains(e.target))closeHelp(); }});
document.addEventListener("keydown",e=>{{ if(e.key==="Escape")closeHelp(); }});

// ── Section collapse ──────────────────────────────────────────────────────
function toggleSection(id){{
  const sec=document.getElementById(id); if(!sec)return;
  sec.classList.toggle("collapsed");
  try{{localStorage.setItem("sec_"+id,sec.classList.contains("collapsed")?"1":"0");}}catch(e){{}}
}}
function expandSection(id){{
  const sec=document.getElementById(id); if(sec)sec.classList.remove("collapsed");
  try{{localStorage.setItem("sec_"+id,"0");}}catch(e){{}}
}}
function restoreSections(){{
  document.querySelectorAll(".report-section").forEach(sec=>{{
    try{{if(localStorage.getItem("sec_"+sec.id)==="1")sec.classList.add("collapsed");}}catch(e){{}}
  }});
}}

// ── Sidebar ───────────────────────────────────────────────────────────────
function toggleSidebar(){{
  document.body.classList.toggle("nav-collapsed");
  try{{localStorage.setItem("nav_collapsed",document.body.classList.contains("nav-collapsed")?"1":"0");}}catch(e){{}}
}}
function restoreSidebar(){{
  try{{if(localStorage.getItem("nav_collapsed")==="1")document.body.classList.add("nav-collapsed");}}catch(e){{}}
}}

// ── View switching ────────────────────────────────────────────────────────
function showView(id){{
  document.querySelectorAll(".view").forEach(v=>v.style.display="none");
  const v=document.getElementById("view-"+id);
  if(v)v.style.display="";

  // Compare re-uses the Summary nav (model list); per-model views have their own context
  const navCtxId = id==="compare" ? "summary" : id;
  document.querySelectorAll(".nav-ctx").forEach(n=>n.style.display="none");
  const nc=document.getElementById("nav-ctx-"+navCtxId);
  if(nc)nc.style.display="";

  document.querySelectorAll(".topbar-tab").forEach(t=>t.classList.toggle("active",t.dataset.view===id));
  try{{localStorage.setItem("active_view",id);}}catch(e){{}}
  window.scrollTo(0,0);
}}
function restoreView(){{
  try{{
    const v=localStorage.getItem("active_view");
    if(v&&document.getElementById("view-"+v))showView(v);
  }}catch(e){{}}
}}

// ── AIBOM per model ────────────────────────────────────────────────────────
const AIBOMS=[]; const AIBOM_NAMES=[];
{aibom_js_vars}
function downloadAibom(idx){{
  try{{
    const blob=new Blob([JSON.stringify(AIBOMS[idx],null,2)],{{type:"application/json"}});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a"); a.href=url; a.download=AIBOM_NAMES[idx];
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }}catch(e){{alert("AIBOM download failed: "+e.message);}}
}}

// ── Chevron animation ─────────────────────────────────────────────────────
document.querySelectorAll("details").forEach(d=>{{
  const chev=d.querySelector(".chev"); if(!chev)return;
  const upd=()=>chev.style.transform=d.open?"rotate(180deg)":"";
  d.addEventListener("toggle",upd); upd();
}});

// ── Init ──────────────────────────────────────────────────────────────────
restoreSections();
restoreSidebar();
restoreView();
</script>
</body>
</html>'''

    out.write_text(doc, encoding="utf-8")
    return str(out)
